INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'm_and_a',
  'accretion_dilution',
  'wiedergabe',
  2,
  'Was versteht man unter einer Akkretion bzw. Dilution im Kontext einer M&A-Transaktion, und woran misst man diese?',
  'Akkretion und Dilution beschreiben die Veränderung des Gewinns je Aktie (EPS) des Käufers nach einer Akquisition im Vergleich zum Stand-alone-EPS vor der Transaktion. Ist das Pro-forma-EPS nach dem Zusammenschluss höher als das ursprüngliche EPS des Käufers, spricht man von einer Akkretion; ist es niedriger, liegt eine Dilution vor. Die Berechnung erfolgt, indem man das kombinierte Nettoeinkommen durch die neue, nach der Transaktion ausstehende Aktienanzahl dividiert und das Ergebnis mit dem ursprünglichen EPS des Käufers vergleicht. Eine Transaktion gilt typischerweise dann als akkretiv, wenn das Kurs-Gewinn-Verhältnis (KGV) des Targets niedriger ist als das des Käufers – bei einer reinen Aktientransaktion.',
  ARRAY['Gewinn je Aktie (EPS)', 'Pro-forma EPS nach Transaktion', 'Vergleich mit Stand-alone EPS des Käufers', 'Akkretion = EPS steigt, Dilution = EPS sinkt', 'Neue Aktienanzahl nach Transaktion']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'm_and_a',
  'accretion_dilution',
  'wiedergabe',
  4,
  'Wie verändert sich die Accretion-/Dilution-Analyse, wenn der Käufer die Akquisition teilweise mit neu ausgegebenen Aktien und teilweise mit Fremdkapital finanziert – und welche gegenläufigen Effekte auf den Pro-forma-EPS müssen dabei zwingend berücksichtigt werden?',
  'Bei einer gemischten Finanzierung aus Aktien und Fremdkapital wirken zwei gegenläufige Effekte auf den Pro-forma-EPS. Die Aktienkomponente erhöht die Anzahl der ausstehenden Aktien (Denominatoreffekt) und verwässert damit den EPS, während die Fremdkapitalkomponente zusätzliche Zinsaufwendungen erzeugt, die – nach Steuern mit dem Faktor (1 – Steuersatz) – den Zähler (Net Income) reduzieren. Gleichzeitig entfällt auf den mit Fremdkapital finanzierten Teil keine zusätzliche Aktienverwässerung, was relativ akkretiv wirkt verglichen mit einer reinen Aktienfinanzierung. Der Break-even-Punkt (Indifferenz-EPS) verschiebt sich je nach Mischungsverhältnis, da höherer Fremdkapitalanteil den Zinsaufwand steigert, aber die Aktienverwässerung begrenzt. Für eine korrekte Analyse müssen daher sowohl der inkrementelle Zinsaufwand nach Steuern als auch die neu ausgegebenen Aktien simultan in Zähler und Nenner des Pro-forma-EPS eingerechnet werden.',
  ARRAY['Denominatoreffekt (neue Aktien verwässern EPS)', 'Zinsaufwand nach Steuern reduziert Net Income (Zählereffekt)', 'gegenläufige Effekte bei gemischter Finanzierung', 'Break-even / Indifferenz-EPS verschiebt sich je nach Mischungsverhältnis', 'simultane Anpassung von Zähler und Nenner im Pro-forma-EPS']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'm_and_a',
  'accretion_dilution',
  'anwendung',
  2,
  'Unternehmen A hat einen Gewinn je Aktie (EPS) von 4,00 € und 50 Millionen ausstehende Aktien. Es erwirbt Unternehmen B für 200 Millionen € in einem reinen Aktientausch. Der Kaufpreis entspricht dem Eigenkapitalwert von B. Unternehmen B hat einen Jahresüberschuss von 20 Millionen €. Der Aktienkurs von A beträgt 40 €. Ist die Transaktion akkretiv oder dilutiv, und warum?',
  'Um die Transaktion zu beurteilen, berechnen wir zunächst die neu ausgegebenen Aktien von A: 200 Mio. € ÷ 40 € = 5 Millionen neue Aktien. Das kombinierte Unternehmen hat damit 55 Millionen Aktien und einen kombinierten Gewinn von 200 Mio. € + 20 Mio. € = 220 Mio. €. Das neue EPS beträgt 220 Mio. € ÷ 55 Mio. = 4,00 € – identisch mit dem ursprünglichen EPS. Die Transaktion ist weder akkretiv noch dilutiv, sondern neutral. Das liegt daran, dass das Kurs-Gewinn-Verhältnis (KGV) beider Unternehmen gleich ist: A handelt zu einem KGV von 10x (40 € ÷ 4 €), und B wird ebenfalls zu 10x erworben (200 Mio. € ÷ 20 Mio. €).',
  ARRAY['Neue Aktien berechnen (200 Mio. ÷ 40 € = 5 Mio.)', 'Kombiniertes EPS (220 Mio. ÷ 55 Mio. = 4,00 €)', 'Neutral – weder akkretiv noch dilutiv', 'Gleiches KGV (10x) als Erklärung', 'KGV-Vergleich als Entscheidungsregel']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'm_and_a',
  'accretion_dilution',
  'anwendung',
  4,
  'Acquiror A hat einen Aktienkurs von 40 €, 200 Mio. Aktien ausstehend und einen Nettogewinn von 320 Mio. €. Target T hat einen Nettogewinn von 80 Mio. € und wird für 1,6 Mrd. € vollständig in Aktien erworben. Die Transaktion generiert keine Synergien. Ist die Transaktion für A akkretiv oder dilutiv – und warum ändert sich das Ergebnis, wenn A stattdessen 50 % Aktien und 50 % Fremdkapital (Zinssatz 5 %, Steuersatz 25 %) zur Finanzierung nutzt?',
  'Im reinen Aktientausch gibt A neue Aktien im Wert von 1,6 Mrd. € aus, also 40 Mio. neue Aktien (1.600 / 40 €), womit die Gesamtaktienzahl auf 240 Mio. steigt. Das kombinierte EPS beträgt (320 + 80) Mio. € / 240 Mio. = 1,667 €, verglichen mit dem ursprünglichen EPS von 320 / 200 = 1,60 €. Die Transaktion ist also leicht akkretiv (+4,2 %), weil das implizite P/E des Targets (1.600 / 80 = 20x) unter dem P/E des Acquirors (40 € × 200 Mio. / 320 Mio. € = 25x) liegt. Im gemischten Finanzierungsszenario werden 800 Mio. € Fremdkapital aufgenommen; die Nachsteuer-Zinskosten betragen 800 Mio. × 5 % × (1 – 25 %) = 30 Mio. €. Es werden nur 20 Mio. neue Aktien ausgegeben (800 / 40 €), sodass das kombinierte EPS (320 + 80 – 30) / 220 Mio. = 370 / 220 = 1,682 € beträgt – stärker akkretiv (+5,1 %), da der Fremdkapitaleinsatz den EPS-Verwässerungseffekt durch weniger neue Aktien reduziert, solange die Nachsteuer-Fremdkapitalkosten unter der Earnings Yield des Targets liegen.',
  ARRAY['Implizites P/E des Targets vs. P/E des Acquirors (Bewertungsrelation)', 'EPS-Berechnung: neue Aktienanzahl und kombinierter Nettogewinn', 'Nachsteuer-Zinskosten bei Fremdkapitalfinanzierung', 'Weniger neue Aktien bei gemischter Finanzierung → geringere Verwässerung', 'Earnings Yield als Vergleichsgröße zu Fremdkapitalkosten']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'm_and_a',
  'accretion_dilution',
  'verstaendnis',
  2,
  'Was bedeutet es, wenn eine Akquisition „akkretiv" oder „dilutiv" auf den Gewinn je Aktie (EPS) des Käufers ist, und wovon hängt das grundsätzlich ab?',
  'Eine Akquisition ist akkretiv, wenn der EPS des Käufers nach dem Zusammenschluss steigt, und dilutiv, wenn er sinkt. Entscheidend ist dabei das Verhältnis zwischen dem Kurs-Gewinn-Verhältnis (KGV) des Käufers und dem impliziten KGV, das für das Zielunternehmen gezahlt wird: Kauft ein Unternehmen mit hohem KGV ein Zielunternehmen zu einem niedrigeren KGV, ist der Deal in der Regel akkretiv. Bei einer reinen Aktientransaktion gilt: Liegt die Gewinnrendite (Earnings Yield) des Targets über der des Käufers, ist der Deal akkretiv. Bei Cash-Finanzierung kommt es darauf an, ob die Nachsteuerrendite des eingesetzten Kapitals die Kapitalkosten übersteigt.',
  ARRAY['EPS-Veränderung nach Transaktion', 'KGV-Vergleich Käufer vs. Ziel', 'Earnings Yield', 'Finanzierungsart (Aktien vs. Cash)', 'Akkretiv vs. Dilutiv']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'm_and_a',
  'accretion_dilution',
  'verstaendnis',
  4,
  'Ein Unternehmen finanziert eine Akquisition vollständig mit Aktien und die Transaktion ist auf EPS-Basis akkretiv – dennoch argumentiert Ihr Senior-Banker, dass die Transaktion für die Aktionäre des Käufers wertvernichtend sein könnte. Wie ist das möglich, und unter welchen Bedingungen trifft dieses Argument zu?',
  'EPS-Akkretion bedeutet lediglich, dass der Gewinn pro Aktie steigt, sagt aber nichts über die Wertschaffung aus – entscheidend ist, ob die implizite Rendite der Akquisition die Kapitalkosten des Käufers übersteigt. Bei einer reinen Aktientransaktion gibt der Käufer Anteile ab; wenn das Tauschverhältnis impliziert, dass der Käufer einen höheren Wert überträgt als er durch die Zielgesellschaft erhält (z. B. weil er ein niedrigeres KGV hat als das Ziel oder eine zu hohe Prämie zahlt), entsteht Verwässerung auf wirtschaftlicher Ebene trotz EPS-Akkretion. Dieser scheinbare Widerspruch tritt typischerweise auf, wenn das Zielunternehmen ein hohes KGV hat und der Käufer durch die Ausgabe von Aktien relativ günstig bewertet wird – die Akkretion entsteht dann rein mechanisch durch den Nennereffekt, nicht durch echte Wertschöpfung. Zusätzlich können überhöhte Synergieerwartungen oder eine zu hohe Akquisitionsprämie dazu führen, dass der Barwert der gezahlten Prämie den Barwert der realisierbaren Synergien übersteigt, was per Definition Wert vernichtet. Ein MD würde daher stets verlangen, die EPS-Analyse durch eine DCF-basierte Wertbeitragsrechnung (Value Creation Analysis) zu ergänzen.',
  ARRAY['EPS-Akkretion ≠ Wertschaffung', 'Kapitalkosten / Rendite der Akquisition', 'KGV-Verhältnis Käufer vs. Ziel (Nennereffekt)', 'Akquisitionsprämie vs. Barwert der Synergien', 'Value Creation Analysis / DCF-Perspektive']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'm_and_a',
  'synergy_valuation',
  'wiedergabe',
  2,
  'Was versteht man unter Synergien im Kontext einer M&A-Transaktion, und welche zwei Hauptkategorien von Synergien werden unterschieden?',
  'Synergien bezeichnen den zusätzlichen Wert, der durch den Zusammenschluss zweier Unternehmen entsteht und der für die Unternehmen alleine nicht erreichbar wäre – zusammengefasst im Prinzip „1 + 1 = 3". Man unterscheidet grundsätzlich zwei Hauptkategorien: Umsatzsynergien (Revenue Synergies) und Kostensynergien (Cost Synergies). Umsatzsynergien entstehen beispielsweise durch Cross-Selling, Zugang zu neuen Märkten oder ein erweitertes Produktportfolio. Kostensynergien resultieren hingegen aus der Eliminierung von Doppelstrukturen, Skaleneffekten oder der Optimierung der Lieferkette. In der Praxis gelten Kostensynergien als leichter quantifizierbar und zuverlässiger realisierbar als Umsatzsynergien.',
  ARRAY['Synergien = Mehrwert durch Zusammenschluss (1+1=3)', 'Umsatzsynergien (Revenue Synergies)', 'Kostensynergien (Cost Synergies)', 'Beispiele für jede Kategorie', 'Kostensynergien leichter quantifizierbar']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'm_and_a',
  'synergy_valuation',
  'wiedergabe',
  4,
  'Wie unterscheidet sich die Bewertung von Cost Synergies und Revenue Synergies im Rahmen einer M&A-Transaktion, und warum werden Revenue Synergies in der Regel mit einem höheren Diskontierungssatz bewertet als Cost Synergies?',
  'Cost Synergies – etwa Einsparungen durch Stellenabbau, Schließung redundanter Standorte oder Einkaufsvorteile – gelten als vergleichsweise sicher und gut quantifizierbar, weshalb sie mit einem niedrigeren Diskontierungssatz (oft WACC oder leicht darüber) abgezinst werden. Revenue Synergies hingegen – wie Cross-Selling-Potenziale, Preiserhöhungsspielräume oder Marktzugang – sind stark von externen Faktoren und Managemententscheidungen abhängig, schwerer prognostizierbar und realisieren sich typischerweise später, was ein höheres Ausführungsrisiko impliziert. Deshalb wird auf Revenue Synergies ein Risk Premium aufgeschlagen, der den Diskontierungssatz gegenüber Cost Synergies um mehrere Prozentpunkte erhöht. In der Praxis werden Revenue Synergies zudem häufig erst zu 50 % oder weniger in den Synergy-NPV eingerechnet (sog. „Haircut"), um konservative Bewertungsannahmen sicherzustellen. Der Gesamtwert der Synergien ergibt sich als NPV der nach Steuern realisierten Synergiecashflows abzüglich der Implementierungskosten (One-time Costs to Achieve).',
  ARRAY['Cost Synergies vs. Revenue Synergies (Risikoprofil)', 'Höherer Diskontierungssatz / Risk Premium für Revenue Synergies', 'Ausführungsrisiko und Prognoseunsicherheit', 'Haircut auf Revenue Synergies', 'NPV abzüglich Costs to Achieve']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'm_and_a',
  'synergy_valuation',
  'anwendung',
  2,
  'Unternehmen A übernimmt Unternehmen B. Die erwarteten jährlichen Kostensynergien betragen 40 Mio. €, die Umsatzsynergien 10 Mio. €. Der kombinierte Steuersatz liegt bei 25 %, und Sie verwenden einen Diskontierungssatz von 10 % sowie eine ewige Rente zur Bewertung. Wie hoch ist der Barwert der Synergien nach Steuern?',
  'Die gesamten Synergien vor Steuern betragen 40 Mio. € + 10 Mio. € = 50 Mio. € pro Jahr. Nach Steuern ergibt sich ein jährlicher Synergiebetrag von 50 Mio. € × (1 – 0,25) = 37,5 Mio. €. Da wir eine ewige Rente annehmen, berechnet sich der Barwert als 37,5 Mio. € ÷ 10 % = 375 Mio. €. Dieser Wert stellt den maximalen Betrag dar, den der Käufer theoretisch als Prämie über den fairen Wert von Unternehmen B zahlen könnte, ohne Wert zu vernichten.',
  ARRAY['Kosten- und Umsatzsynergien addieren (50 Mio. €)', 'Steuerbereinigung (× (1 – Steuersatz) = 37,5 Mio. €)', 'Ewige Rente (÷ Diskontierungssatz)', 'Barwert 375 Mio. €', 'Maximale Akquisitionsprämie']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'm_and_a',
  'synergy_valuation',
  'anwendung',
  4,
  'Ein strategischer Käufer übernimmt ein Zielunternehmen für einen Kaufpreis von 500 Mio. €. Das Zielunternehmen hat ein EBITDA von 40 Mio. €. Der Käufer erwartet jährliche Kostensynergien von 15 Mio. € (vollständig realisierbar ab Jahr 3) sowie einmalige Integrationskosten von 20 Mio. €. Der Steuersatz beträgt 30 %, der WACC 8 %. Das Akquisitions-Multiple beträgt 12,5x EV/EBITDA. Wie berechnen Sie den Barwert der Synergien, und ist der gezahlte Synergy Premium gerechtfertigt?',
  'Der Barwert der Kostensynergien ergibt sich als Perpetuity der nach-Steuer-Synergien: 15 Mio. € × (1 – 0,30) = 10,5 Mio. € p.a., diskontiert mit dem WACC von 8 % ergibt einen Barwert von 10,5 / 0,08 = 131,25 Mio. €. Da die Synergien erst ab Jahr 3 vollständig realisiert werden, ist dieser Wert um den Anlaufeffekt zu korrigieren – vereinfacht kann man die fehlenden Cashflows der Jahre 1 und 2 abziehen, was den Barwert auf ca. 113–120 Mio. € reduziert. Der Synergy Premium entspricht der Differenz zwischen gezahltem Kaufpreis und dem Stand-alone-Wert des Targets: Bei einem Markt-Multiple von z. B. 10x wäre der Stand-alone-Wert 400 Mio. €, der Premium beträgt also 100 Mio. €. Da der Barwert der Nettosynergien (nach Integrationskosten: ~113 Mio. € – 20 Mio. € = ~93 Mio. €) unter dem gezahlten Premium von 100 Mio. € liegt, ist der Kaufpreis grenzwertig nicht gerechtfertigt – der Käufer zahlt mehr als er an Synergiewert erhält. Entscheidend ist zudem, ob Umsatzsynergien oder Steuervorteile den verbleibenden Gap schließen können.',
  ARRAY['Nach-Steuer-Synergien (15 Mio. × 0,7 = 10,5 Mio. €)', 'Perpetuity-Barwert (10,5 / 8% = 131,25 Mio. €)', 'Phasenkorrektur / Ramp-up (Synergien erst ab Jahr 3)', 'Synergy Premium = Kaufpreis minus Stand-alone-Wert', 'Netto-Synergiewert nach Integrationskosten vs. Premium-Vergleich']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'm_and_a',
  'synergy_valuation',
  'verstaendnis',
  2,
  'Was versteht man unter Kosten- und Umsatzsynergien im Rahmen einer M&A-Transaktion, und warum werden Kostensynergien in der Regel höher bewertet als Umsatzsynergien?',
  'Kostensynergien entstehen durch die Zusammenlegung von Funktionen, den Abbau von Doppelstrukturen und Skaleneffekte – zum Beispiel durch die Reduktion von Personal, IT-Systemen oder Einkaufskosten. Umsatzsynergien hingegen resultieren aus Cross-Selling, Markterweiterung oder der gemeinsamen Nutzung von Vertriebskanälen. Kostensynergien werden höher bewertet, weil sie schneller realisierbar, besser planbar und mit geringerer Unsicherheit behaftet sind. Umsatzsynergien hängen dagegen von externen Faktoren wie Kundenverhalten und Marktentwicklung ab, was ihre Prognose deutlich schwieriger macht. Daher werden Umsatzsynergien in konservativen Bewertungsmodellen oft ganz weggelassen oder stark diskontiert.',
  ARRAY['Kostensynergien (Doppelstrukturen, Skaleneffekte)', 'Umsatzsynergien (Cross-Selling, Markterweiterung)', 'Realisierungswahrscheinlichkeit und Planbarkeit', 'Unsicherheit bei Umsatzsynergien', 'Konservative Bewertung / Diskontierung']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'm_and_a',
  'synergy_valuation',
  'verstaendnis',
  4,
  'Warum werden Kostensynergien in der Regel höher bewertet als Umsatzsynergien gleicher Größe, und unter welchen Umständen könnte diese Annahme falsch sein?',
  'Kostensynergien werden höher bewertet, weil sie in der Regel sicherer, schneller realisierbar und unabhängig vom Marktverhalten sind – etwa durch Headcount-Reduktion, Konsolidierung von Standorten oder Einkaufsvorteile. Umsatzsynergien hingegen hängen von Kundenverhalten, Wettbewerbsreaktionen und Cross-Selling-Erfolg ab, was sie unsicherer und zeitlich verzögerter macht; Analysten diskontieren sie daher stärker oder schließen sie ganz aus dem Base-Case aus. Die Annahme kann jedoch falsch sein, wenn Kostensynergien mit hohen Restrukturierungskosten oder Dis-Synergien verbunden sind – z. B. wenn Entlassungen zu Kundenverlust oder Qualitätseinbußen führen. Ebenso können Umsatzsynergien in Märkten mit hoher Kundenbindung und klarer Produktkomplementarität (z. B. Software-Bundles) sehr zuverlässig und schnell realisierbar sein und damit höher zu bewerten sein als volatile Kosteneinsparungen. Entscheidend ist stets die Kombination aus Realisierungswahrscheinlichkeit, Zeitpunkt des Cash-flow-Eintritts und den damit verbundenen Einmalkosten.',
  ARRAY['Realisierungswahrscheinlichkeit', 'Umsatzsynergien-Unsicherheit', 'Dis-Synergien / Restrukturierungskosten', 'Diskontierung / Timing des Cash-flows', 'Produktkomplementarität als Edge-Case']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'm_and_a',
  'premium_analysis',
  'wiedergabe',
  2,
  'Was versteht man unter einer Akquisitionsprämie im Rahmen einer M&A-Transaktion, und wie wird sie berechnet?',
  'Die Akquisitionsprämie ist der Aufschlag, den ein Käufer über den aktuellen Marktpreis (Börsenkurs) des Zielunternehmens hinaus zahlt, um die Aktionäre zur Zustimmung der Transaktion zu bewegen. Sie wird berechnet als die Differenz zwischen dem angebotenen Kaufpreis je Aktie und dem unbeeinflussten Aktienkurs des Zielunternehmens, dividiert durch den unbeeinflussten Aktienkurs – ausgedrückt in Prozent. Typischerweise liegt die Prämie bei börsennotierten Unternehmen zwischen 20 % und 40 %. Sie spiegelt den Kontrollwert sowie erwartete Synergien wider, die der Käufer durch die Übernahme zu realisieren hofft.',
  ARRAY['Aufschlag auf den unbeeinflussten Aktienkurs', 'Formel: (Kaufpreis – unbeeinflusster Kurs) / unbeeinflusster Kurs', 'Kontrollprämie', 'Synergien', 'typische Höhe 20–40 %']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'm_and_a',
  'premium_analysis',
  'wiedergabe',
  4,
  'Wie wird der Beitrag einer Akquisition zum Gewinn je Aktie des Käufers berechnet, und unter welchen präzisen Bedingungen ist eine Transaktion trotz eines positiven EPS-Accretion-Effekts im ersten Jahr aus Wertschaffungsperspektive dennoch als wertvernichtend einzustufen?',
  'Die EPS-Accretion/-Dilution ergibt sich aus der Differenz zwischen dem erworbenen Nachsteuergewinn (bereinigt um Transaktionskosten und Synergien) und den zusätzlichen Finanzierungskosten – bei einer Aktientransaktion den Opportunitätskosten der neu ausgegebenen Aktien, bei einer Cashfinanzierung den Zinskosten nach Steuern – geteilt durch die neue Aktienanzahl. Eine Transaktion kann jedoch trotz kurzfristiger EPS-Accretion wertvernichtend sein, wenn der gezahlte Kaufpreis eine implizite Rendite (ROIC) unterhalb der gewichteten Kapitalkosten (WACC) des Käufers erzeugt. Dies ist typischerweise der Fall, wenn die Accretion primär durch einen niedrigen Steuersatz, aggressiv angesetzte Synergien oder eine günstige Finanzierungsstruktur getrieben wird, anstatt durch echte operative Wertschöpfung. Der entscheidende Maßstab ist daher nicht der kurzfristige EPS-Effekt, sondern ob der Barwert der zukünftigen Free Cashflows die Gesamtinvestition inklusive Kontrollprämie übersteigt.',
  ARRAY['EPS-Accretion/-Dilution Formel (erworbener Gewinn vs. Finanzierungskosten)', 'ROIC vs. WACC als eigentlicher Wertschaffungsmaßstab', 'Kontrollprämie und deren Einfluss auf die Rendite', 'Synergien als mögliche Verzerrungsquelle der kurzfristigen Accretion', 'Barwert der Free Cashflows als fundamentales Bewertungskriterium']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'm_and_a',
  'premium_analysis',
  'anwendung',
  2,
  'Ein Unternehmen (Acquiror) hat einen Aktienkurs von 40 € und 50 Millionen ausstehende Aktien. Es möchte ein Zielunternehmen übernehmen, das einen Eigenkapitalwert von 600 Millionen € hat. Der Acquiror bietet eine Prämie von 25 % auf den aktuellen Aktienkurs des Targets. Wie viele neue Aktien muss der Acquiror ausgeben, wenn die Transaktion vollständig in Aktien bezahlt wird?',
  'Der Kaufpreis beträgt 600 Millionen € multipliziert mit dem Faktor 1,25, also 750 Millionen €. Da der Acquiror seine eigenen Aktien zu einem Kurs von 40 € ausgibt, muss er 750 Millionen € ÷ 40 € = 18,75 Millionen neue Aktien emittieren. Nach der Transaktion hat der Acquiror insgesamt 50 + 18,75 = 68,75 Millionen ausstehende Aktien. Das Umtauschverhältnis (Exchange Ratio) gibt an, wie viele Acquiror-Aktien je Target-Aktie getauscht werden – dieser Wert hängt vom Aktienkurs des Targets ab, der hier nicht explizit angegeben ist, weshalb die Berechnung auf Basis des Gesamtkaufpreises erfolgt.',
  ARRAY['Kaufpreis = Eigenkapitalwert × (1 + Prämie) = 750 Mio. €', 'Neue Aktien = Kaufpreis ÷ Aktienkurs Acquiror = 18,75 Mio.', 'Gesamtaktien nach Transaktion = 68,75 Mio.', 'Stock Deal / Aktientausch', 'Verwässerung (Dilution)']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'm_and_a',
  'premium_analysis',
  'anwendung',
  4,
  'Ein strategischer Käufer (EV/EBITDA: 8x, EBITDA: €200 Mio.) übernimmt ein Zielunternehmen (EV/EBITDA: 10x, EBITDA: €50 Mio.) vollständig mit Cash. Der Käufer erwartet jährliche Synergien von €20 Mio. EBITDA ab Jahr 1. Ist die Transaktion für den Käufer EPS-akkretiv oder -dilutiv, und welchen maximalen Kaufpreis (EV) würde ein rationaler Käufer zahlen, wenn er sein eigenes Bewertungsmultiple nicht verwässern möchte?',
  'Der Käufer bewertet sich selbst mit 8x × €200 Mio. = €1.600 Mio. EV; das Ziel kostet aktuell 10x × €50 Mio. = €500 Mio. Mit Synergien steigt das kombinierte EBITDA auf €270 Mio. (€200 + €50 + €20). Damit der Käufer sein Multiple von 8x nicht verwässert, darf der kombinierte EV maximal 8x × €270 Mio. = €2.160 Mio. betragen – abzüglich des Käufer-EV von €1.600 Mio. ergibt sich ein maximaler Ziel-EV von €560 Mio. (entspricht einem impliziten Synergie-adjustierten Multiple von 11,2x auf das Stand-alone-EBITDA des Targets). Da der Kaufpreis von €500 Mio. unter dieser Schwelle liegt, ist die Transaktion multiple-akkretiv; bei einer Cash-Finanzierung hängt die EPS-Akkretion zusätzlich vom entgangenen Zinsergebnis (Opportunitätskosten) ab, das gegen den EBITDA-Gewinn gerechnet werden muss.',
  ARRAY['Kombiniertes EBITDA inkl. Synergien (€270 Mio.)', 'Maximaler Ziel-EV = 8x × €270 Mio. − €1.600 Mio. = €560 Mio.', 'Multiple-Verwässerungstest (Accretion/Dilution auf EV/EBITDA-Basis)', 'Opportunitätskosten der Cash-Finanzierung (entgangene Zinsen) für EPS-Analyse', 'Synergie-adjustiertes implizites Kaufpreis-Multiple']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'm_and_a',
  'premium_analysis',
  'verstaendnis',
  2,
  'Warum wird bei einer M&A-Transaktion häufig eine Akquisitionsprämie gezahlt, und welche Faktoren bestimmen deren Höhe?',
  'Eine Akquisitionsprämie wird gezahlt, weil der Käufer bereit ist, mehr als den aktuellen Marktwert des Zielunternehmens zu entrichten, um die Aktionäre zur Zustimmung zu bewegen und die Kontrolle über das Unternehmen zu erlangen. Die Prämie spiegelt die erwarteten Synergien wider – also Kosten- und Umsatzsynergien, die durch die Zusammenführung beider Unternehmen entstehen sollen. Darüber hinaus spielen strategische Überlegungen wie der Zugang zu neuen Märkten, Technologien oder Talenten eine Rolle. Die Höhe der Prämie wird durch den Wettbewerb unter potenziellen Bietern, die Verhandlungsstärke des Targets sowie die aktuelle Marktbewertung beeinflusst. Typischerweise liegt die Kontrollprämie bei börsennotierten Unternehmen zwischen 20 % und 40 % über dem ungestörten Aktienkurs.',
  ARRAY['Kontrollprämie', 'Synergien', 'Zustimmung der Aktionäre', 'Wettbewerb unter Bietern', 'ungestörter Aktienkurs']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'm_and_a',
  'premium_analysis',
  'verstaendnis',
  4,
  'Ein Käufer erwirbt ein Unternehmen und plant, den Goodwill nach dem Closing für Steuerzwecke abzuschreiben. Unter welchen Bedingungen ist dies möglich, und welche Trade-offs entstehen dabei zwischen Käufer und Verkäufer in der Transaktionsstrukturierung?',
  'Eine steuerliche Abschreibung von Goodwill ist im Rahmen eines Asset Deals oder einer Section-338(h)(10)-Wahl (im US-Kontext) möglich, da dabei die Vermögenswerte auf eine neue Steuerbasis (Stepped-up Basis) gehoben werden. Im Gegensatz dazu entsteht beim Share Deal kein steuerlich abschreibungsfähiger Goodwill auf Käuferseite, da die historische Steuerbasis der Zielgesellschaft fortgeführt wird. Der Trade-off liegt darin, dass Verkäufer beim Asset Deal häufig höhere Steuern zahlen – insbesondere durch die Umqualifizierung von Kapitalgewinnen in ordentliches Einkommen bei bestimmten Vermögenswerten –, weshalb sie typischerweise einen Kaufpreisaufschlag (Gross-up) verlangen. Der Käufer muss daher abwägen, ob der Barwert der künftigen Steuerersparnisse aus der Goodwill-Abschreibung den höheren Kaufpreis rechtfertigt. In der Praxis wird dieser Vorteil oft geteilt, indem der Käufer einen Teil seiner Steuerersparnis als Preisaufschlag an den Verkäufer weitergibt.',
  ARRAY['Asset Deal vs. Share Deal', 'Stepped-up Basis', 'Steuerliche Goodwill-Abschreibung', 'Gross-up / Kaufpreisaufschlag', 'Barwert der Steuerersparnisse']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'accounting',
  'three_statement_link',
  'wiedergabe',
  2,
  'Wie sind die drei Kernabschlüsse – Gewinn- und Verlustrechnung, Bilanz und Kapitalflussrechnung – miteinander verknüpft?',
  'Der Jahresüberschuss aus der Gewinn- und Verlustrechnung fließt als erste Position in den operativen Teil der Kapitalflussrechnung ein und erhöht gleichzeitig das Eigenkapital in der Bilanz. Die Kapitalflussrechnung erklärt die Veränderung des Zahlungsmittelbestands, dessen Endwert direkt in der Bilanz unter den liquiden Mitteln ausgewiesen wird. Veränderungen von Bilanzpositionen des Working Capitals – wie Forderungen oder Verbindlichkeiten – schlagen sich wiederum im operativen Cashflow nieder. Auf diese Weise sind alle drei Abschlüsse konsistent miteinander verbunden und müssen sich gegenseitig abstimmen.',
  ARRAY['Jahresüberschuss (GuV → Eigenkapital & Kapitalflussrechnung)', 'Eigenkapital-Verknüpfung (Bilanz)', 'Endbestand liquide Mittel (Kapitalflussrechnung → Bilanz)', 'Working-Capital-Veränderungen', 'Konsistenz / Abstimmung der drei Abschlüsse']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'accounting',
  'three_statement_link',
  'wiedergabe',
  4,
  'Wie verändert eine Abschreibung (D&A) von 100 € alle drei Abschlüsse – und welchen Netto-Effekt hat sie auf den Kassenbestand, wenn der Steuersatz 30 % beträgt?',
  'In der GuV reduziert die Abschreibung von 100 € das EBIT um 100 € und damit den Nettogewinn um 70 € (nach 30 % Steuern). In der Kapitalflussrechnung wird der Nettogewinn um 100 € nach oben korrigiert (non-cash add-back), sodass der operative Cashflow per saldo um +30 € steigt. In der Bilanz sinkt der Buchwert des Anlagevermögens um 100 €, während die Gewinnrücklagen um 70 € abnehmen und die Steuerschulden (bzw. latente Steuern) um 30 € sinken – die Bilanzsumme bleibt damit ausgeglichen. Der Netto-Kasseneffekt beträgt +30 €, da nur die Steuerersparnis (Tax Shield) als echter Cashzufluss wirkt; die Abschreibung selbst ist zahlungsunwirksam.',
  ARRAY['EBIT-Reduktion um 100 €, Nettogewinn-Reduktion um 70 €', 'Non-cash Add-back in der Kapitalflussrechnung (+100 €)', 'Netto-Kasseneffekt +30 € (Tax Shield)', 'Buchwert Anlagevermögen −100 €, Gewinnrücklagen −70 €', 'Zahlungsunwirksam – nur Steuerersparnis ist echter Cashflow']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'accounting',
  'three_statement_link',
  'anwendung',
  2,
  'Ein Unternehmen schreibt zusätzliche Abschreibungen in Höhe von 50 € ab. Der Steuersatz beträgt 40 %. Wie verändern sich GuV, Bilanz und Kapitalflussrechnung?',
  'In der GuV sinkt das EBIT um 50 €, und nach Steuern (40 %) reduziert sich der Jahresüberschuss um 30 €. In der Bilanz verringert sich der Sachanlagewert um 50 €, die Steuerverbindlichkeiten sinken um 20 € und das Eigenkapital (Gewinnrücklagen) geht um 30 € zurück. In der Kapitalflussrechnung wird der niedrigere Jahresüberschuss (−30 €) im operativen Cashflow durch das Hinzuaddieren der nicht zahlungswirksamen Abschreibung (+50 €) korrigiert, sodass der operative Cashflow per saldo um +20 € steigt. Der Investitions- und Finanzierungscashflow bleibt unverändert.',
  ARRAY['Jahresüberschuss sinkt um 30 € (nach Steuern)', 'Sachanlagewert sinkt um 50 €', 'Eigenkapital sinkt um 30 €', 'Abschreibung wird im operativen Cashflow wieder hinzuaddiert', 'Operativer Cashflow steigt netto um 20 €']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'accounting',
  'three_statement_link',
  'anwendung',
  4,
  'Ein Unternehmen aktiviert eine selbst entwickelte Maschine mit Herstellungskosten von 500.000 € und einer Nutzungsdauer von 5 Jahren (lineare Abschreibung, kein Restwert). Die Maschine wird vollständig mit einem endfälligen Bankdarlehen zu 4 % p.a. finanziert. Wie verändern sich GuV, Bilanz und Kapitalflussrechnung im ersten Jahr nach Inbetriebnahme – und welcher Effekt auf den Free Cash Flow ergibt sich im Vergleich zu einer sofortigen Ausgabe ohne Aktivierung?',
  'In der GuV werden im ersten Jahr 100.000 € Abschreibung (500.000 € / 5 Jahre) sowie 20.000 € Zinsaufwand (500.000 € × 4 %) erfasst; das EBIT sinkt um 100.000 €, das EBT um 120.000 €. In der Bilanz steht die Maschine mit 400.000 € (Nettowert nach Abschreibung) auf der Aktivseite, das Darlehen von 500.000 € auf der Passivseite. In der Kapitalflussrechnung erscheint der Kauf als Investitions-Cashflow (–500.000 €), während die Abschreibung im operativen Cashflow wieder addiert wird; der Zinsaufwand ist je nach Darstellungswahlrecht operativ oder im Finanzierungsbereich. Der Free Cash Flow (FCF = operativer CF – Capex) ist im Aktivierungsjahr identisch mit dem Szenario ohne Aktivierung, da der Mittelabfluss in beiden Fällen 500.000 € beträgt – der Unterschied liegt lediglich in der zeitlichen Verteilung des GuV-Aufwands (einmalig vs. über 5 Jahre verteilt), nicht im tatsächlichen Cash-Effekt.',
  ARRAY['Abschreibung 100.000 € in GuV, Buchwert 400.000 € in Bilanz', 'Zinsaufwand 20.000 € (EBT-Effekt)', 'Capex –500.000 € im Investitions-Cashflow', 'Abschreibung als nicht-zahlungswirksame Korrektur im operativen CF', 'FCF identisch – kein Cash-Unterschied zur Sofortausgabe']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'accounting',
  'three_statement_link',
  'verstaendnis',
  2,
  'Wie verändert eine Abschreibung (Depreciation) von 100 € die drei Abschlüsse – GuV, Bilanz und Kapitalflussrechnung?',
  'In der GuV reduziert die Abschreibung von 100 € den EBIT und damit den Vorsteuergewinn um 100 €; bei einem Steuersatz von 40 % sinkt der Nettogewinn um 60 €. In der Bilanz nimmt der Buchwert des Anlagevermögens um 100 € ab, während das Eigenkapital (Gewinnrücklagen) um 60 € sinkt; die latente Steuerschuld reduziert sich um 40 €. In der Kapitalflussrechnung wird der Nettogewinn im operativen Cashflow um 100 € nach oben korrigiert (nicht-zahlungswirksamer Aufwand), sodass der operative Cashflow insgesamt um 40 € steigt. Die Abschreibung selbst ist zahlungsunwirksam – der tatsächliche Mittelabfluss fand bereits beim Kauf des Anlageguts statt.',
  ARRAY['Nettogewinn sinkt um 60 € (nach Steuern)', 'Anlagevermögen in der Bilanz sinkt um 100 €', 'Eigenkapital sinkt um 60 €', 'Nicht-zahlungswirksame Korrektur im operativen Cashflow (+100 €)', 'Operativer Cashflow steigt netto um 40 €']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'accounting',
  'three_statement_link',
  'verstaendnis',
  4,
  'Ein Unternehmen wechselt seine Abschreibungsmethode von der linearen zur degressiven Methode. Wie wirkt sich das auf alle drei Abschlüsse im Jahr des Wechsels aus – und warum kehrt sich der Effekt in späteren Jahren um?',
  'Im Jahr des Wechsels steigt die Abschreibung, da die degressive Methode in frühen Perioden höhere Beträge ansetzt. Das führt zu einem niedrigeren EBIT und Nettogewinn in der GuV, während im Cashflow-Statement der operative Cashflow steigt, weil die höhere nicht-zahlungswirksame Abschreibung zurückaddiert wird. In der Bilanz sinkt der Buchwert des Anlagevermögens stärker, und das Eigenkapital reduziert sich durch den niedrigeren Jahresüberschuss. In späteren Jahren dreht sich der Effekt um: Die degressive Abschreibung fällt geringer aus als die lineare, was zu höherem Gewinn, höherem Eigenkapital und einem niedrigeren operativen Cashflow im Vergleich zur linearen Methode führt – der kumulierte Gesamteffekt über die Nutzungsdauer ist jedoch identisch, da beide Methoden denselben Gesamtbetrag abschreiben.',
  ARRAY['Degressive Abschreibung höher in frühen Jahren → niedrigerer EBIT/Nettogewinn', 'Operativer Cashflow steigt (nicht-zahlungswirksame Korrektur)', 'Buchwert Anlagevermögen und Eigenkapital sinken stärker', 'Effektumkehr in späteren Jahren (geringere Abschreibung → höherer Gewinn)', 'Kumulierter Gesamteffekt über Nutzungsdauer identisch']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'accounting',
  'working_capital',
  'wiedergabe',
  2,
  'Wie ist das Working Capital definiert und wie lautet die entsprechende Formel?',
  'Das Working Capital (Nettoumlaufvermögen) misst die kurzfristige Liquidität eines Unternehmens und ergibt sich aus der Differenz von kurzfristigem Umlaufvermögen und kurzfristigen Verbindlichkeiten: Working Capital = Current Assets − Current Liabilities. Zu den Current Assets zählen typischerweise Forderungen aus Lieferungen und Leistungen, Vorräte sowie Kassenbestände. Auf der anderen Seite umfassen die Current Liabilities vor allem Verbindlichkeiten aus Lieferungen und Leistungen sowie sonstige kurzfristige Verbindlichkeiten. Ein positives Working Capital bedeutet, dass das Unternehmen seine kurzfristigen Verpflichtungen aus dem laufenden Betrieb decken kann.',
  ARRAY['Current Assets minus Current Liabilities', 'Kurzfristige Liquidität', 'Forderungen und Vorräte (Current Assets)', 'Verbindlichkeiten aus Lieferungen und Leistungen (Current Liabilities)', 'Positives Working Capital = kurzfristige Zahlungsfähigkeit']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'accounting',
  'working_capital',
  'wiedergabe',
  4,
  'Ein Unternehmen verlängert seine Kreditorenlaufzeit (Days Payable Outstanding) von 30 auf 60 Tage, während gleichzeitig die Debitorenlaufzeit (Days Sales Outstanding) von 45 auf 60 Tage steigt. Wie verändert sich der Cash Conversion Cycle, und welchen Nettoeffekt hat das auf den operativen Cash Flow – und warum ist diese Betrachtung allein unzureichend, um die Working-Capital-Effizienz zu beurteilen?',
  'Der Cash Conversion Cycle (CCC) berechnet sich als DSO + DIO – DPO. In diesem Fall steigt der DSO um 15 Tage, während der DPO um 30 Tage zunimmt; der CCC verkürzt sich also um netto 15 Tage (unter der Annahme, dass DIO konstant bleibt), was den operativen Cash Flow kurzfristig verbessert, da weniger Kapital im Umlaufvermögen gebunden ist. Allerdings ist diese isolierte Betrachtung unzureichend: Ein steigender DSO kann auf Bonitätsprobleme der Kunden oder nachlassendes Inkasso-Management hinweisen und das Ausfallrisiko erhöhen. Ebenso birgt eine aggressive Verlängerung der Kreditorenlaufzeit das Risiko, Lieferantenbeziehungen zu belasten oder Skonti zu verlieren, was die tatsächlichen Finanzierungskosten erhöht. Eine vollständige Beurteilung der Working-Capital-Effizienz erfordert daher die Analyse von Trends, Branchenvergleichen sowie qualitativen Faktoren wie Lieferanten- und Kundenbonität.',
  ARRAY['Cash Conversion Cycle (DSO + DIO – DPO)', 'Nettoverkürzung des CCC um 15 Tage', 'Verbesserung des operativen Cash Flows durch geringere Kapitalbindung', 'Steigender DSO als Warnsignal für Ausfallrisiko', 'Risiko durch aggressive DPO-Verlängerung (Lieferantenbeziehungen, Skontoverlust)']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'accounting',
  'working_capital',
  'anwendung',
  2,
  'Ein Unternehmen hat folgende Bilanzpositionen: Forderungen aus Lieferungen und Leistungen 80 Mio. €, Vorräte 40 Mio. €, Verbindlichkeiten aus Lieferungen und Leistungen 50 Mio. €, Kassenbestand 30 Mio. €. Wie hoch ist das Net Working Capital?',
  'Das Net Working Capital (NWC) berechnet sich als kurzfristige operative Aktiva minus kurzfristige operative Passiva. In diesem Fall zählen Forderungen (80 Mio. €) und Vorräte (40 Mio. €) zu den operativen Umlaufvermögenspositionen, während der Kassenbestand in der klassischen IB-Definition des operativen NWC ausgeschlossen wird. Die Verbindlichkeiten aus Lieferungen und Leistungen (50 Mio. €) stellen die operative kurzfristige Verbindlichkeit dar. Das Net Working Capital beträgt demnach 80 + 40 − 50 = 70 Mio. €. Ein positives NWC bedeutet, dass das Unternehmen mehr kurzfristiges Kapital in seinen operativen Positionen gebunden hat als es durch Lieferantenverbindlichkeiten finanziert.',
  ARRAY['Net Working Capital = operative Umlaufvermögen − operative kurzfristige Verbindlichkeiten', 'Forderungen und Vorräte als operative Aktiva', 'Verbindlichkeiten aus L&L als operative Passiva', 'Kassenbestand wird beim operativen NWC ausgeschlossen', 'Ergebnis: 70 Mio. €']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'accounting',
  'working_capital',
  'anwendung',
  4,
  'Ein Unternehmen hat folgende Bilanzpositionen zum Jahresende: Forderungen aus Lieferungen und Leistungen 120 Mio. €, Vorräte 80 Mio. €, Verbindlichkeiten aus Lieferungen und Leistungen 90 Mio. €, sonstige kurzfristige Rückstellungen 30 Mio. €, Kassenbestand 50 Mio. €. Der Jahresumsatz beträgt 600 Mio. €, die Herstellungskosten (COGS) 360 Mio. €. Berechnen Sie den Net Working Capital sowie den Cash Conversion Cycle – und erläutern Sie, warum der Kassenbestand und die kurzfristigen Rückstellungen bei der operativen Working-Capital-Analyse typischerweise ausgeschlossen werden.',
  'Das operative Net Working Capital (NWC) umfasst ausschließlich betrieblich gebundenes Kapital: Forderungen (120) + Vorräte (80) – Verbindlichkeiten (90) = 110 Mio. €. Kassenbestand wird ausgeschlossen, da er nicht operativ gebunden, sondern frei disponierbar ist und in der Finanzierungsstruktur (Nettoverschuldung) berücksichtigt wird; kurzfristige Rückstellungen sind oft nicht-cash und schwankend, weshalb sie das operative Bild verzerren würden. Der Cash Conversion Cycle (CCC) ergibt sich aus DSO + DIO – DPO: DSO = 120/600 × 365 ≈ 73 Tage, DIO = 80/360 × 365 ≈ 81 Tage, DPO = 90/360 × 365 ≈ 91 Tage, CCC ≈ 73 + 81 – 91 = 63 Tage. Ein CCC von 63 Tagen bedeutet, dass das Unternehmen im Schnitt 63 Tage Kapital im operativen Kreislauf bindet, bevor es Mittelzuflüsse realisiert – ein zentraler Hebel für Free-Cash-Flow-Optimierung.',
  ARRAY['Operatives NWC = Forderungen + Vorräte – Verbindlichkeiten (110 Mio. €)', 'Kassenbestand gehört zur Nettoverschuldung, nicht zum operativen NWC', 'Kurzfristige Rückstellungen sind nicht-cash und nicht-operativ', 'Cash Conversion Cycle (DSO + DIO – DPO ≈ 63 Tage)', 'COGS als Basis für DIO und DPO, Umsatz als Basis für DSO']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'accounting',
  'working_capital',
  'verstaendnis',
  2,
  'Warum wird ein Anstieg der Forderungen aus Lieferungen und Leistungen (Accounts Receivable) in der Kapitalflussrechnung als Mittelabfluss behandelt?',
  'Ein Anstieg der Forderungen bedeutet, dass das Unternehmen Umsätze bereits in der GuV erfasst hat, das entsprechende Geld aber noch nicht erhalten hat. Da der Nettogewinn diese Umsätze bereits enthält, muss der Anstieg der Forderungen im operativen Cashflow subtrahiert werden, um vom Gewinn auf den tatsächlichen Zahlungsmittelzufluss überzuleiten. Im Kern spiegelt dies den Unterschied zwischen der Accrual-Buchführung und der tatsächlichen Kassenbewegung wider. Je höher die ausstehenden Forderungen, desto mehr Kapital ist im Working Capital gebunden und steht dem Unternehmen nicht als liquide Mittel zur Verfügung.',
  ARRAY['Accrual-Buchführung vs. tatsächlicher Zahlungseingang', 'Umsatz bereits in GuV erfasst, Geld noch nicht erhalten', 'Subtraktion im operativen Cashflow', 'Kapital im Working Capital gebunden', 'Überleitung vom Nettogewinn zum operativen Cashflow']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'accounting',
  'working_capital',
  'verstaendnis',
  4,
  'Ein Unternehmen verlängert seine Kreditorenlaufzeit (Days Payable Outstanding) von 30 auf 60 Tage, um den Free Cash Flow zu verbessern. Unter welchen Umständen kann diese Maßnahme trotzdem den Unternehmenswert langfristig schädigen?',
  'Eine Verlängerung der DPO verbessert kurzfristig den operativen Cash Flow durch die Freisetzung von Working Capital, kann aber langfristig wertvernichtend sein. Wenn Lieferanten als Reaktion Skonti streichen oder höhere Einkaufspreise durchsetzen, steigen die COGS und der EBIT sinkt – der Kapitalkosten-Vorteil wird durch Margenverluste überkompensiert. Zudem kann eine aggressive Zahlungspolitik die Lieferantenbeziehungen beschädigen, Versorgungsrisiken erhöhen und in kapitalintensiven Branchen die Verhandlungsmacht gegenüber kritischen Zulieferern dauerhaft schwächen. In Branchen mit knappen Lieferketten kann dies sogar zu Produktionsunterbrechungen führen, die den Umsatz direkt belasten. Schließlich signalisiert eine erzwungene DPO-Ausweitung dem Kapitalmarkt potenziell Liquiditätsprobleme, was die Fremdkapitalkosten erhöhen und den WACC negativ beeinflussen kann.',
  ARRAY['Skonto-Verlust / steigende Einkaufspreise (COGS-Effekt)', 'Lieferantenbeziehungen und Versorgungsrisiko', 'Working-Capital-Optimierung vs. Margenerosion (Trade-off)', 'Signalwirkung auf Kapitalmarkt / WACC', 'DPO-Grenze: erzwungen vs. verhandelt']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'accounting',
  'dcf_fcf_bridge',
  'wiedergabe',
  2,
  'Wie leitet man ausgehend vom EBIT den Free Cash Flow to Firm (FCFF) ab? Nennen Sie die einzelnen Schritte der Überleitung.',
  'Der Free Cash Flow to Firm ergibt sich aus dem EBIT, indem man zunächst Steuern auf das EBIT abzieht, um das NOPAT (Net Operating Profit After Tax) zu erhalten. Anschließend werden nicht zahlungswirksame Posten wie Abschreibungen (D&A) wieder addiert. Danach zieht man die Investitionsausgaben (CapEx) ab und berücksichtigt die Veränderung des Working Capitals (ΔNWC). Die Formel lautet vereinfacht: FCFF = EBIT × (1 – Steuersatz) + D&A – CapEx – ΔNWC.',
  ARRAY['NOPAT (EBIT × (1 – Steuersatz))', 'Abschreibungen (D&A) addieren', 'CapEx abziehen', 'Veränderung Working Capital (ΔNWC)', 'FCFF-Formel']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'accounting',
  'dcf_fcf_bridge',
  'wiedergabe',
  4,
  'Beim Übergang vom EBIT zum Free Cash Flow to Firm (FCFF) im DCF-Modell werden mehrere Anpassungen vorgenommen. Welche konkreten Positionen werden addiert bzw. subtrahiert, und warum führt die Behandlung von Zinsen dabei zu einem konzeptionellen Unterschied gegenüber dem Free Cash Flow to Equity (FCFE)?',
  'Der FCFF ergibt sich aus dem EBIT nach Steuern (NOPAT = EBIT × (1 – Steuersatz)), zuzüglich Abschreibungen (nicht-zahlungswirksam), abzüglich Investitionen (CapEx) und abzüglich der Veränderung des Working Capitals. Zinsen werden beim FCFF bewusst nicht abgezogen, da dieser Cash Flow allen Kapitalgebern – Eigen- und Fremdkapitalgebern – zur Verfügung steht und mit dem WACC diskontiert wird. Der FCFE hingegen zieht Zinsen (nach Steuern) ab und addiert die Nettoneuverschuldung, da er nur den Anteil der Eigenkapitalgeber abbildet und mit den Eigenkapitalkosten (Ke) diskontiert wird. Der konzeptionelle Unterschied liegt also darin, dass FCFF kapitalstrukturunabhängig ist, während FCFE die Finanzierungsstruktur explizit berücksichtigt.',
  ARRAY['NOPAT (EBIT × (1 – t))', 'Abschreibungen addieren, CapEx und ΔWorking Capital subtrahieren', 'Zinsen beim FCFF nicht abgezogen (alle Kapitalgeber)', 'WACC vs. Eigenkapitalkosten (Ke)', 'FCFE: Zinsen (nach Steuern) abziehen und Nettoneuverschuldung addieren']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'accounting',
  'dcf_fcf_bridge',
  'anwendung',
  2,
  'Ein Unternehmen hat folgende Kennzahlen für das abgelaufene Geschäftsjahr: EBIT = 200 Mio. €, Steuersatz = 25 %, Abschreibungen (D&A) = 40 Mio. €, Investitionen (CapEx) = 60 Mio. €, Erhöhung des Working Capitals = 20 Mio. €. Berechnen Sie den Free Cash Flow to Firm (FCFF).',
  'Der FCFF berechnet sich ausgehend vom EBIT nach Steuern (NOPAT): 200 Mio. € × (1 – 0,25) = 150 Mio. €. Anschließend werden die nicht zahlungswirksamen Abschreibungen addiert (+40 Mio. €), die Investitionen subtrahiert (–60 Mio. €) und die Erhöhung des Working Capitals subtrahiert (–20 Mio. €). Der FCFF beträgt damit 150 + 40 – 60 – 20 = 110 Mio. €. Dieser Wert repräsentiert den Cashflow, der allen Kapitalgebern – sowohl Eigen- als auch Fremdkapitalgebern – zur Verfügung steht und bildet die Grundlage für den Enterprise-Value-DCF.',
  ARRAY['NOPAT (EBIT × (1 – Steuersatz))', 'D&A addieren', 'CapEx subtrahieren', 'Veränderung Working Capital subtrahieren', 'Ergebnis 110 Mio. €']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'accounting',
  'dcf_fcf_bridge',
  'anwendung',
  4,
  'Ein Unternehmen weist folgende Kennzahlen für das abgelaufene Geschäftsjahr aus: EBITDA 200 Mio. €, Abschreibungen (D&A) 40 Mio. €, Veränderung des Working Capital –25 Mio. € (Anstieg), Capex 50 Mio. €, Steuersatz 30 %. Zusätzlich wurden im Jahr einmalig 15 Mio. € Restrukturierungskosten als zahlungswirksamer Aufwand verbucht. Berechnen Sie den unlevered Free Cash Flow (FCF) und erläutern Sie, wie Sie mit den Restrukturierungskosten umgehen und warum.',
  'Der unlevered FCF berechnet sich ausgehend vom EBIT: EBIT = EBITDA – D&A = 200 – 40 = 160 Mio. €; NOPAT = 160 × (1 – 0,30) = 112 Mio. €; FCF = 112 + 40 – 25 – 50 = 77 Mio. €. Die Restrukturierungskosten sind bereits im EBITDA enthalten und damit im EBIT und NOPAT steuermindernd berücksichtigt – ein separater Abzug wäre ein Doppelzähler. Im DCF-Kontext ist jedoch zu prüfen, ob die Kosten wirklich einmalig sind: Wenn ja, sollte man für die Normalisierung des EBITDA die 15 Mio. € herausrechnen (bereinigtes EBITDA = 215 Mio. €) und den FCF auf Basis des normalisierten EBIT neu berechnen (EBIT = 175 Mio. €; NOPAT = 122,5 Mio. €; FCF = 87,5 Mio. €). Die Entscheidung hängt davon ab, ob die Restrukturierungskosten für die Prognoseperiode repräsentativ sind oder nicht – ein strenger MD würde genau diese Unterscheidung einfordern.',
  ARRAY['NOPAT (EBIT × (1 – Steuersatz))', 'D&A Add-back', 'Working Capital Veränderung (Anstieg = Mittelabfluss)', 'Einmalkosten / Normalisierung des EBITDA', 'Doppelzählung vermeiden']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'accounting',
  'dcf_fcf_bridge',
  'verstaendnis',
  2,
  'Warum addieren wir beim Übergang vom EBIT zum Free Cash Flow die Abschreibungen wieder hinzu, obwohl sie zuvor bereits als Aufwand abgezogen wurden?',
  'Abschreibungen sind ein nicht-zahlungswirksamer Aufwand – sie reduzieren zwar den buchhalterischen Gewinn, führen aber zu keinem tatsächlichen Mittelabfluss. Im DCF-Modell interessiert uns der tatsächlich verfügbare Zahlungsmittelfluss, weshalb wir nicht-zahlungswirksame Posten wie Abschreibungen wieder addieren müssen. Ausgangspunkt ist das EBIT, das bereits um Abschreibungen gemindert wurde; durch das Wiederhinzuaddieren stellen wir den operativen Cash-Charakter der Größe wieder her. Der eigentliche Investitionsaufwand wird stattdessen separat über die Capex-Position im Free-Cash-Flow-Übergang berücksichtigt, um eine Doppelzählung zu vermeiden.',
  ARRAY['nicht-zahlungswirksam', 'Abschreibungen addieren', 'EBIT zu FCF Übergang', 'Capex separat', 'Doppelzählung vermeiden']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'accounting',
  'dcf_fcf_bridge',
  'verstaendnis',
  4,
  'Ein Unternehmen hat hohe aktivierte Entwicklungskosten (Capitalized Development Costs), die jährlich amortisiert werden. Wie wirkt sich das auf den Free Cash Flow im DCF-Modell aus, und wo genau liegt der methodische Unterschied zur Behandlung von R&D-Aufwendungen unter US-GAAP?',
  'Unter IFRS dürfen Entwicklungskosten aktiviert und über die Nutzungsdauer amortisiert werden, während US-GAAP R&D grundsätzlich sofort als Aufwand verbucht. Im DCF-Modell wird der Free Cash Flow aus dem EBIT (nach Amortisierung) abgeleitet: Die Amortisierung der aktivierten Kosten mindert das EBIT, wird aber im Übergang zum FCF als nicht-zahlungswirksamer Posten wieder addiert – analog zur Abschreibung. Der eigentliche Zahlungsabfluss ist jedoch die Investitionsauszahlung (Capex) zum Zeitpunkt der Aktivierung, die im FCF als Abzug erscheint. Unter US-GAAP hingegen trifft der Aufwand sofort das EBIT und den NOPAT, ohne einen separaten Capex-Abzug – der Gesamteffekt auf den FCF über die Laufzeit ist identisch, aber der zeitliche Ausweis unterscheidet sich erheblich. Ein Analyst muss daher bei IFRS-Unternehmen prüfen, ob aktivierte Entwicklungskosten wirtschaftlich eher Capex oder laufendem Aufwand entsprechen, um Vergleichbarkeit herzustellen.',
  ARRAY['Aktivierung vs. Sofortaufwand (IFRS vs. US-GAAP)', 'Amortisierung als nicht-zahlungswirksamer Posten (Add-back im FCF)', 'Capex-Abzug zum Zeitpunkt der Aktivierung', 'Zeitlicher Unterschied im FCF-Ausweis trotz identischem Gesamteffekt', 'Vergleichbarkeitsanpassung für Analysten']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'valuation',
  'wacc_calc',
  'wiedergabe',
  2,
  'Wie lautet die Formel für den WACC, und was bedeuten die einzelnen Komponenten?',
  'Der WACC (Weighted Average Cost of Capital) berechnet sich als gewichteter Durchschnitt der Eigenkapital- und Fremdkapitalkosten: WACC = (E/V) × ke + (D/V) × kd × (1 – t). Dabei steht E für den Marktwert des Eigenkapitals, D für den Marktwert des Fremdkapitals und V = E + D für den Gesamtunternehmenswert. ke bezeichnet die Eigenkapitalkosten, kd die Fremdkapitalkosten vor Steuern, und (1 – t) berücksichtigt den steuerlichen Vorteil der Fremdfinanzierung (Tax Shield), da Zinsen steuerlich absetzbar sind. Die Gewichte E/V und D/V geben den jeweiligen Anteil am Gesamtkapital an und sollten auf Basis von Marktwerten berechnet werden.',
  ARRAY['Eigenkapitalkosten (ke) und Fremdkapitalkosten (kd)', 'Gewichtung nach Marktwerten (E/V und D/V)', 'Steuerlicher Vorteil / Tax Shield: kd × (1 – t)', 'V = E + D als Gesamtkapital', 'Formel: WACC = (E/V) × ke + (D/V) × kd × (1 – t)']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'valuation',
  'wacc_calc',
  'wiedergabe',
  4,
  'Beim WACC verwenden Praktiker für die Eigenkapitalkosten häufig den risikofreien Zinssatz einer 10-jährigen Staatsanleihe – warum nicht die kurzfristige 3-Monats-Rate, und welche konzeptionelle Inkonsistenz entsteht, wenn man dennoch die kurzfristige Rate wählt?',
  'Der risikofreie Zinssatz im CAPM soll die Opportunitätskosten eines langfristigen, risikolosen Investments widerspiegeln, da Unternehmensbewertungen auf langfristigen Free Cashflows basieren – die Duration der Anleihe sollte also zur Duration der Cashflows passen. Die 3-Monats-Rate ist zwar nahezu risikofrei, aber sie enthält eine implizite Wiederanlageprämie und spiegelt kurzfristige Zentralbankpolitik wider, nicht die langfristige Zeitpräferenz des Marktes. Verwendet man die kurzfristige Rate, entsteht eine konzeptionelle Inkonsistenz: Die Diskontierungsrate ist zu niedrig angesetzt, weil die normale Zinsstrukturkurve eine positive Laufzeitprämie (Term Premium) enthält, die bei langfristigen Cashflows berücksichtigt werden muss. Zudem ist das Beta im CAPM typischerweise gegen einen langfristigen Marktindex geschätzt, was die Verwendung eines kurzfristigen risikofreien Zinssatzes in derselben Formel methodisch inkonsistent macht. In der Praxis wird daher fast ausnahmslos die 10-jährige Staatsanleiherendite (z. B. Bund oder US-Treasury) als Proxy verwendet.',
  ARRAY['Laufzeitkongruenz (Duration der Cashflows)', 'Term Premium / Laufzeitprämie', 'CAPM-Konsistenz (Beta vs. Marktindex)', 'Kurzfristige Rate reflektiert Zentralbankpolitik', '10-jährige Staatsanleihe als Marktstandard']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'valuation',
  'wacc_calc',
  'anwendung',
  2,
  'Ein Unternehmen hat folgende Kapitalstruktur: Eigenkapital (Marktwert) 600 Mio. €, Fremdkapital (Marktwert) 400 Mio. €. Der risikofreie Zinssatz beträgt 2 %, die Marktrisikoprämie 6 %, und das Beta des Unternehmens liegt bei 1,2. Die Fremdkapitalkosten vor Steuern betragen 4 %, der Steuersatz 30 %. Berechnen Sie den WACC.',
  'Die Eigenkapitalkosten berechnen sich nach dem CAPM: k_E = 2 % + 1,2 × 6 % = 9,2 %. Die Gewichte betragen 60 % Eigenkapital und 40 % Fremdkapital (Gesamtkapital = 1.000 Mio. €). Die steuerbereinigten Fremdkapitalkosten sind 4 % × (1 − 0,30) = 2,8 %. Der WACC ergibt sich damit als: WACC = 0,60 × 9,2 % + 0,40 × 2,8 % = 5,52 % + 1,12 % = 6,64 %. Der Tax Shield auf das Fremdkapital reduziert die effektiven Fremdkapitalkosten und damit den WACC gegenüber den unbereinigten Kosten.',
  ARRAY['CAPM für Eigenkapitalkosten (k_E = rf + β × MRP)', 'Marktwert-Gewichte (60/40)', 'Tax Shield: k_D × (1 − t)', 'WACC-Formel: Gewichtete Summe der Kapitalkosten', 'Ergebnis: 6,64 %']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'valuation',
  'wacc_calc',
  'anwendung',
  4,
  'Ein Unternehmen hat folgende Kapitalstruktur: 600 Mio. € Eigenkapital (Marktwert), 400 Mio. € Fremdkapital (Marktwert). Der risikofreie Zinssatz beträgt 2 %, die Marktrisikoprämie 6 %, Beta 1,3, der Fremdkapitalkostensatz vor Steuern 4,5 % und der Steuersatz 30 %. Während der Due Diligence stellen Sie fest, dass das Unternehmen zusätzlich 150 Mio. € an Operating Leases hat, die bisher nicht in der Kapitalstruktur berücksichtigt wurden. Wie berechnen Sie den angepassten WACC, und welchen Effekt haben die kapitalisierten Operating Leases auf das Ergebnis?',
  'Zunächst berechne ich den ursprünglichen WACC: Eigenkapitalkosten = 2 % + 1,3 × 6 % = 9,8 %; Gewichte: EK 60 %, FK 40 %; WACC = 0,6 × 9,8 % + 0,4 × 4,5 % × (1 – 0,30) = 5,88 % + 1,26 % = 7,14 %. Nach Kapitalisierung der Operating Leases erhöht sich das Fremdkapital auf 550 Mio. € (400 + 150), die Gesamtkapitalbasis auf 1.150 Mio. €; die neuen Gewichte sind EK ≈ 52,2 % und FK ≈ 47,8 %. Da Operating-Lease-Verbindlichkeiten wie besichertes Fremdkapital behandelt werden, verwende ich denselben oder einen leicht niedrigeren FK-Kostensatz; der angepasste WACC beträgt dann ca. 0,522 × 9,8 % + 0,478 × 4,5 % × 0,70 ≈ 5,12 % + 1,51 % = 6,63 %. Der WACC sinkt, weil günstigeres (steuerlich abzugsfähiges) Fremdkapital einen größeren Anteil einnimmt – gleichzeitig muss das EBIT um die impliziten Leasingzinsen bereinigt und der Free Cash Flow entsprechend angepasst werden, damit DCF und WACC konsistent bleiben.',
  ARRAY['Operating Leases kapitalisieren (Fremdkapital +150 Mio. €)', 'Neue Kapitalstrukturgewichte (EK ~52 %, FK ~48 %)', 'Eigenkapitalkosten via CAPM (9,8 %)', 'Tax Shield auf FK-Kosten (1 – Steuersatz)', 'WACC sinkt durch höheren FK-Anteil; EBIT/FCF-Anpassung erforderlich']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'valuation',
  'wacc_calc',
  'verstaendnis',
  2,
  'Warum verwendet man beim WACC die Marktwerte von Eigen- und Fremdkapital anstelle der Buchwerte?',
  'Der WACC soll die tatsächlichen Opportunitätskosten der Kapitalgeber widerspiegeln, wie sie heute am Markt bewertet werden – nicht historische Anschaffungskosten. Marktwerte zeigen, was Investoren aktuell für Eigen- und Fremdkapital zahlen würden, und spiegeln damit die realen Renditeerwartungen wider. Buchwerte hingegen basieren auf historischen Bilanzierungsregeln und können stark von der wirtschaftlichen Realität abweichen, etwa bei stark gestiegenem Eigenkapitalwert oder abgeschriebenen Vermögenswerten. Da der WACC zur Diskontierung zukünftiger Cashflows genutzt wird, muss er auf zukunftsorientierten, marktbasierten Größen beruhen. Nur so ergibt sich eine konsistente Bewertung, bei der Diskontierungssatz und diskontierte Cashflows auf denselben Marktannahmen basieren.',
  ARRAY['Opportunitätskosten', 'Marktwerte vs. Buchwerte', 'aktuelle Renditeerwartungen', 'Konsistenz mit Cashflow-Diskontierung', 'historische Bilanzwerte ungeeignet']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'valuation',
  'wacc_calc',
  'verstaendnis',
  4,
  'Warum kann die Verwendung des aktuellen Marktwerts des Fremdkapitals anstelle des Buchwerts bei der WACC-Berechnung in einem Hochzinsumfeld zu einer systematischen Verzerrung führen, und in welche Richtung wirkt diese Verzerrung auf den WACC?',
  'Im WACC wird Fremdkapital idealerweise zu Marktwerten gewichtet, da diese die tatsächlichen Opportunitätskosten widerspiegeln. In einem Hochzinsumfeld sinkt der Marktwert bestehender Anleihen (mit niedrigerem Kupon) unter den Buchwert, was den Anteil des Fremdkapitals an der Gesamtkapitalisierung zu Marktwerten reduziert. Dadurch steigt das Eigenkapitalgewicht im WACC, und da Eigenkapital teurer ist als Fremdkapital, erhöht sich der WACC gegenüber einer Buchwert-basierten Berechnung. Gleichzeitig steigt der Fremdkapitalkostensatz (Kd) selbst, weil neue Finanzierungen zu höheren Marktzinsen erfolgen müssen. Die Verzerrung wirkt also in Richtung eines zu niedrigen WACCs, wenn man Buchwerte statt Marktwerte verwendet – ein besonders relevanter Edge-Case bei Unternehmen mit großem, langfristigem Altschuldenbestand.',
  ARRAY['Marktwert vs. Buchwert Fremdkapital', 'Inverse Beziehung Zinsen und Anleihekurs', 'Eigenkapitalgewicht steigt bei Marktwertberechnung', 'WACC-Verzerrung nach oben (Marktwert) vs. unten (Buchwert)', 'Fremdkapitalkostensatz Kd steigt im Hochzinsumfeld']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'valuation',
  'comps_selection',
  'wiedergabe',
  2,
  'Nach welchen Kriterien wählt man vergleichbare Unternehmen (Comparable Companies) für eine Trading-Comps-Analyse aus?',
  'Bei der Auswahl vergleichbarer Unternehmen orientiert man sich primär an der Branchenzugehörigkeit, da Unternehmen im gleichen Sektor ähnliche Geschäftsmodelle und Risikoprofile aufweisen. Darüber hinaus sollten die Peers in Bezug auf Unternehmensgröße – gemessen etwa an Umsatz oder Market Cap – sowie Wachstumsprofil und Profitabilität (z. B. EBITDA-Marge) möglichst ähnlich sein. Geografische Präsenz und das operative Geschäftsmodell (z. B. B2B vs. B2C, Produkt vs. Dienstleistung) sind weitere relevante Faktoren. In der Praxis beginnt man mit einem breiten Universum und grenzt es anhand dieser Kriterien schrittweise ein, bis eine handhabbare Peer Group von typischerweise 6–12 Unternehmen entsteht.',
  ARRAY['Branchenzugehörigkeit / Sektor', 'Unternehmensgröße (Umsatz, Market Cap)', 'Wachstumsprofil und Profitabilität (Margen)', 'Geschäftsmodell / operationale Ähnlichkeit', 'Peer Group Umfang (6–12 Unternehmen)']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'valuation',
  'comps_selection',
  'wiedergabe',
  4,
  'Welche konkreten Kriterien verwendest du zur Auswahl vergleichbarer Unternehmen für eine Trading-Comps-Analyse, und wie gehst du vor, wenn ein Kriterium mit einem anderen in Konflikt gerät – etwa wenn ein Unternehmen zwar dieselbe Branche hat, aber eine fundamental andere Kapitalstruktur aufweist?',
  'Die Auswahl von Comparables basiert primär auf vier Kriterien: Branchenzugehörigkeit und Geschäftsmodell, Größe (Umsatz, EBITDA, Market Cap), geografische Präsenz sowie Wachstums- und Margenprofil. Bei einem Konflikt zwischen Branchenrelevanz und Kapitalstruktur priorisiere ich in der Regel die operative Vergleichbarkeit – also Geschäftsmodell, Margen und Wachstum – da Kapitalstrukturunterschiede durch die Verwendung von Enterprise-Value-Multiples (z. B. EV/EBITDA) weitgehend neutralisiert werden. Ein Unternehmen mit stark abweichendem Leverage kann dennoch als Comparable aufgenommen werden, sollte aber im Kommentar explizit als Ausreißer gekennzeichnet werden. Equity-Value-Multiples wie KGV hingegen sind kapitalstrukturabhängig und erfordern eine sorgfältigere Bereinigung oder den Ausschluss des betreffenden Unternehmens. Letztlich ist die Auswahl ein Urteilsurteil: Man strebt eine Peer Group an, die eng genug ist, um aussagekräftig zu sein, aber breit genug, um statistisch robust zu bleiben.',
  ARRAY['operative Vergleichbarkeit (Geschäftsmodell, Margen, Wachstum)', 'EV-Multiples neutralisieren Kapitalstrukturunterschiede', 'Equity-Value-Multiples sind kapitalstrukturabhängig', 'Ausreißer-Kennzeichnung / Sensitivitätsanalyse', 'Peer-Group-Breite vs. Vergleichbarkeit (Trade-off)']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'valuation',
  'comps_selection',
  'anwendung',
  2,
  'Du bewertest ein mittelständisches deutsches Softwareunternehmen mit einem EBITDA von 40 Mio. € und einem Umsatzwachstum von 15 % p.a. Aus einer Liste von zehn potenziellen Vergleichsunternehmen hast du folgende Kandidaten identifiziert: (A) ein US-amerikanischer Enterprise-Software-Konzern mit 8 Mrd. € Umsatz und 5 % Wachstum, (B) drei europäische SaaS-Anbieter mit ähnlichem Wachstum (12–18 %) und EBITDA-Margen von 20–30 %, sowie (C) ein deutsches IT-Beratungsunternehmen mit vergleichbarer Größe, aber nur 3 % Wachstum. Welche Unternehmen würdest du in deine Peer Group aufnehmen und warum?',
  'In die Peer Group würde ich primär die drei europäischen SaaS-Anbieter (Gruppe B) aufnehmen, da sie hinsichtlich Geschäftsmodell, Wachstumsprofil (12–18 %) und EBITDA-Margen am besten vergleichbar sind. Den US-amerikanischen Konzern (A) würde ich ausschließen, da er mit 8 Mrd. € Umsatz eine völlig andere Größenordnung aufweist und das geringere Wachstum von 5 % auf ein reiferes Geschäftsmodell hindeutet – beides verzerrt die Multiples erheblich. Das IT-Beratungsunternehmen (C) scheidet ebenfalls aus, weil es trotz ähnlicher Größe ein fundamental anderes Geschäftsmodell (Dienstleistung statt Software) und ein deutlich niedrigeres Wachstum hat, was zu strukturell anderen Bewertungsniveaus führt. Entscheidend bei der Peer-Group-Auswahl sind stets Geschäftsmodell, Wachstum, Profitabilität und Größe als Hauptkriterien.',
  ARRAY['Geschäftsmodell-Vergleichbarkeit (SaaS vs. Beratung)', 'Wachstumsprofil als Auswahlkriterium', 'Größe / Umsatzskala als Verzerrungsfaktor', 'Multiple-Verzerrung durch unpassende Peers', 'Europäische SaaS-Anbieter als beste Vergleichsgruppe']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'valuation',
  'comps_selection',
  'anwendung',
  4,
  'Sie bewerten ein mittelständisches deutsches Softwareunternehmen (SaaS, 80 % Recurring Revenue, EBITDA-Marge 12 %, starkes Wachstum von 25 % p.a.) und haben folgende vier potenzielle Vergleichsunternehmen identifiziert: (A) ein US-amerikanischer SaaS-Konzern mit 30 % Wachstum und 35 % EBITDA-Marge, (B) ein europäischer IT-Dienstleister mit 3 % Wachstum und 14 % EBITDA-Marge, (C) ein deutsches ERP-Unternehmen mit 8 % Wachstum, 18 % EBITDA-Marge und 60 % Recurring Revenue, (D) ein börsennotierter US-SaaS-Anbieter mit 22 % Wachstum, 10 % EBITDA-Marge und 85 % Recurring Revenue. Welche Unternehmen würden Sie in Ihre Peer Group aufnehmen, welche ausschließen, und wie gehen Sie mit den verbleibenden Unterschieden in der Peer Group um?',
  'Ich würde Unternehmen A und D als Kernpeers aufnehmen, da beide ein hohes Recurring-Revenue-Modell und vergleichbares Wachstumsprofil aufweisen – die entscheidenden Werttreiber bei SaaS-Unternehmen. Unternehmen B würde ich ausschließen, da es ein reiner IT-Dienstleister mit projektbasiertem Umsatz und minimalem Wachstum ist und damit ein fundamental anderes Geschäftsmodell repräsentiert. Unternehmen C ist ein Grenzfall: Das ERP-Modell hat strukturelle Ähnlichkeiten, aber mit nur 60 % Recurring Revenue und 8 % Wachstum ist das Profil deutlich schwächer – ich würde es allenfalls als sekundären Peer mit entsprechendem Abschlag verwenden. Die verbleibenden Unterschiede – insbesondere die höhere Marge von A – adressiere ich durch Normalisierung auf EV/Revenue statt EV/EBITDA als primäres Multiple, da EBITDA-Margen bei Wachstumsunternehmen stark von Reinvestitionsentscheidungen abhängen, sowie durch eine Regressionsanalyse (z. B. EV/Revenue vs. Wachstumsrate), um ein adjustiertes Multiple für das Zielunternehmen abzuleiten.',
  ARRAY['Recurring Revenue als primäres Auswahlkriterium', 'Ausschluss IT-Dienstleister (anderes Geschäftsmodell)', 'EV/Revenue statt EV/EBITDA bei unterschiedlichen Margen', 'Regressionsanalyse / Wachstumsadjustierung', 'Grenzfall ERP-Peer mit Begründung']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'valuation',
  'comps_selection',
  'verstaendnis',
  2,
  'Welche Kriterien verwendest du, um vergleichbare Unternehmen für eine Trading-Comps-Analyse auszuwählen?',
  'Bei der Auswahl vergleichbarer Unternehmen orientiere ich mich primär an der Branchenzugehörigkeit und dem Geschäftsmodell, da Unternehmen mit ähnlichen Umsatztreibern und Kostenstrukturen am ehesten vergleichbare Bewertungsmultiples aufweisen. Zusätzlich achte ich auf ähnliche Unternehmensgrößen – gemessen an Umsatz, EBITDA oder Marktkapitalisierung – sowie auf vergleichbare Wachstumsraten und Margenprofile. Geografische Präsenz und das regulatorische Umfeld spielen ebenfalls eine Rolle, da diese die Risikostruktur und damit die Bewertung beeinflussen. In der Praxis ist eine perfekte Vergleichbarkeit selten erreichbar, weshalb man typischerweise eine Peer Group von fünf bis zehn Unternehmen bildet und Ausreißer bei der Interpretation der Multiples gesondert berücksichtigt.',
  ARRAY['Branchenzugehörigkeit / Geschäftsmodell', 'Unternehmensgröße (Umsatz, EBITDA, Marktkapitalisierung)', 'Wachstumsrate und Margenprofile', 'Geografische Präsenz / regulatorisches Umfeld', 'Peer Group Bildung (5–10 Unternehmen)']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'valuation',
  'comps_selection',
  'verstaendnis',
  4,
  'Sie bewerten ein hochprofitables Softwareunternehmen mit 40 % EBITDA-Marge und wählen Vergleichsunternehmen aus. Zwei potenzielle Comps haben ähnliche Wachstumsraten, aber deutlich niedrigere Margen von 15–20 %. Warum kann die Aufnahme dieser Unternehmen in Ihre Peer Group trotzdem gerechtfertigt sein – und welche Anpassungen müssten Sie vornehmen?',
  'Unternehmen mit ähnlichem Geschäftsmodell, Wachstumsprofil und Kapitalstruktur können grundsätzlich relevante Comps sein, selbst wenn die Margen abweichen – denn der Markt bewertet primär Wachstum und Skalierbarkeit, nicht allein die aktuelle Profitabilität. Entscheidend ist, ob die Margendifferenz strukturell ist (z. B. unterschiedliche Investitionsphase, höhere R&D-Intensität) oder dauerhaft, da temporäre Unterschiede durch Forward-Multiples oder normalisierte Margen bereinigt werden können. Man sollte die rohen EV/EBITDA-Multiples um die Margendifferenz adjustieren, etwa durch Regression (z. B. EV/EBITDA vs. EBITDA-Marge) oder durch Verwendung von EV/Revenue als ergänzendem Multiplikator, der margenunabhängig ist. Alternativ bietet sich ein PEG-ähnlicher Ansatz an, bei dem das Multiple durch die Wachstumsrate geteilt wird, um Wachstums- und Bewertungsunterschiede zu normalisieren. Letztlich muss der Analyst transparent machen, dass die Peer Group inhomogen ist, und die resultierende Bewertungsspanne entsprechend breiter ansetzen oder die Comps mit unterschiedlicher Gewichtung versehen.',
  ARRAY['Margendifferenz strukturell vs. temporär', 'EV/Revenue als margenunabhängiger Multiplikator', 'Regressions-Adjustierung (Multiple vs. Marge)', 'Forward-Multiples / normalisierte Margen', 'Transparenz über Peer-Group-Inhomogenität']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'valuation',
  'exit_multiple',
  'wiedergabe',
  2,
  'Was ist ein Exit-Multiple im Rahmen einer DCF-Analyse, und wie wird der Terminal Value damit berechnet?',
  'Das Exit-Multiple ist eine Methode zur Berechnung des Terminal Value in einer DCF-Analyse. Dabei wird ein branchenübliches Bewertungsmultiplikator – häufig EV/EBITDA – auf eine Kennzahl des letzten Prognosejahres angewendet. Die Formel lautet: Terminal Value = EBITDA im letzten Prognosejahr × Exit-Multiple. Das resultierende Ergebnis wird anschließend auf den heutigen Zeitpunkt abdiskontiert, um den Barwert des Terminal Value zu erhalten. Das Exit-Multiple spiegelt wider, zu welchem Vielfachen ein vergleichbares Unternehmen am Ende des Prognosezeitraums verkauft werden könnte.',
  ARRAY['Terminal Value', 'EV/EBITDA-Multiplikator', 'letztes Prognosejahr', 'Abdiskontierung', 'Vergleichsunternehmen (Comps)']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'valuation',
  'exit_multiple',
  'wiedergabe',
  4,
  'Beim Exit Multiple-Verfahren in einer LBO-Analyse wird typischerweise ein EV/EBITDA-Multiple auf das EBITDA im Exit-Jahr angewendet – welche konzeptionelle Inkonsistenz entsteht, wenn man dabei dasselbe Multiple wie beim Entry verwendet, und wie sollte man damit in der Praxis umgehen?',
  'Wenn Entry- und Exit-Multiple identisch gesetzt werden, impliziert man eine vollständige Multiple-Expansion oder -Kompression von null – also dass der Markt das Unternehmen zum Exit-Zeitpunkt exakt gleich bewertet wie beim Kauf. Das ist konzeptionell inkonsistent, weil sich Wachstumsprofil, Verschuldungsgrad, Marktumfeld und Reife des Unternehmens über die Haltedauer typischerweise verändern. In der Praxis wird deshalb ein konservativerer Exit-Multiple angesetzt, der leicht unter dem Entry-Multiple liegt, um einen potenziellen Multiple-Kontraktion-Effekt (z. B. durch höheres Unternehmensalter oder veränderte Marktbewertungen) zu berücksichtigen. Zusätzlich sollte der Exit-Multiple mit aktuellen Peer-Group-Multiples und Transaktionspräzedenzfällen plausibilisiert werden, um Zirkularität und Overoptimismus zu vermeiden. Eine Sensitivitätsanalyse über eine Bandbreite von Exit-Multiples ist daher Standard, um die IRR-Abhängigkeit vom Multiple-Niveau transparent zu machen.',
  ARRAY['Multiple-Kontraktion/-Expansion', 'Entry- vs. Exit-Multiple-Inkonsistenz', 'konservativer Exit-Multiple-Ansatz', 'Peer-Group-Plausibilisierung', 'Sensitivitätsanalyse / IRR-Abhängigkeit']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'valuation',
  'exit_multiple',
  'anwendung',
  2,
  'Ein Private-Equity-Fonds kauft ein Unternehmen für einen Entry-EV von 200 Mio. €, wobei das aktuelle EBITDA 20 Mio. € beträgt. Nach 5 Jahren wird ein EBITDA von 35 Mio. € erwartet. Der Fonds plant, das Unternehmen zum gleichen EV/EBITDA-Multiple wie beim Kauf zu verkaufen. Wie hoch ist der Exit-EV?',
  'Der Entry-EV/EBITDA-Multiple berechnet sich als 200 Mio. € ÷ 20 Mio. € = 10x. Da das Exit-Multiple identisch mit dem Entry-Multiple ist (sogenannte „Multiple Neutrality"), ergibt sich der Exit-EV als 10x multipliziert mit dem Exit-EBITDA von 35 Mio. €, also 350 Mio. €. Der Wertzuwachs von 150 Mio. € ist in diesem Fall ausschließlich auf das EBITDA-Wachstum zurückzuführen, nicht auf eine Multiple-Expansion. In der Praxis ist die Annahme eines konstanten Exit-Multiples ein konservativer Ausgangspunkt für LBO-Modelle.',
  ARRAY['Entry-Multiple 10x', 'Exit-EV 350 Mio. €', 'Multiple Neutrality / konstantes Multiple', 'EBITDA-Wachstum als Werttreiber', 'Exit-EV = Exit-Multiple × Exit-EBITDA']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'valuation',
  'exit_multiple',
  'anwendung',
  4,
  'Ein Private-Equity-Fonds kauft ein Unternehmen für einen Einstandspreis von 10x EV/EBITDA bei einem EBITDA von 50 Mio. €. Nach 5 Jahren beträgt das EBITDA 80 Mio. €, die Nettoverschuldung wurde von 300 Mio. € auf 150 Mio. € abgebaut, und vergleichbare Unternehmen werden aktuell mit 9x EV/EBITDA gehandelt. Wie hoch ist der Equity-Rückfluss beim Exit, und welchen Effekt hat die Multiple-Kompression auf die Rendite – würde der Fonds trotzdem ein attraktives Investment-Ergebnis erzielen?',
  'Beim Einstieg beträgt der EV 500 Mio. € (10x × 50 Mio. €), der Equity-Einsatz liegt bei 200 Mio. € (EV 500 Mio. € minus Nettoverschuldung 300 Mio. €). Beim Exit ergibt sich ein EV von 720 Mio. € (9x × 80 Mio. €), und nach Abzug der Restschuld von 150 Mio. € beläuft sich der Equity-Rückfluss auf 570 Mio. €. Das entspricht einem Money-on-Money-Multiple (MoM) von 2,85x auf den Eigenkapitaleinsatz, was bei 5 Jahren Haltedauer einem IRR von ca. 23 % entspricht – trotz einer Multiple-Kompression von 1x. Die Rendite wird hier primär durch EBITDA-Wachstum (organisches Value Creation) und Schuldenabbau (Deleveraging) getragen, was zeigt, dass Multiple-Expansion zwar ein Renditetreiber ist, aber kein zwingend notwendiger. Ein strenger MD würde zudem darauf hinweisen, dass die Multiple-Kompression den Equity-Wert um ca. 90 Mio. € (1x × 80 Mio. € Exit-EBITDA × Eigenkapitalanteil) reduziert hat und bei höherem Leverage der Effekt deutlich stärker gewesen wäre.',
  ARRAY['Entry/Exit EV-Berechnung (EV/EBITDA × EBITDA)', 'Equity-Rückfluss = Exit-EV minus Nettoverschuldung', 'Money-on-Money-Multiple (MoM) und IRR', 'Multiple-Kompression als negativer Renditetreiber', 'Deleveraging und EBITDA-Wachstum als kompensierende Value-Creation-Hebel']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'valuation',
  'exit_multiple',
  'verstaendnis',
  2,
  'Warum verwendet man beim Exit Multiple im DCF einen Marktmultiplikator anstatt einfach die Cashflows bis in die Unendlichkeit zu diskontieren?',
  'Das Exit Multiple vereinfacht die Bewertung des Terminal Value, indem es annimmt, dass das Unternehmen am Ende des Prognosezeitraums zu einem marktüblichen Multiplikator (z. B. EV/EBITDA) verkauft wird. Dies spiegelt wider, wie Käufer in der Praxis Unternehmen tatsächlich bewerten, und verankert die Annahme in beobachtbaren Marktdaten. Im Gegensatz zur Gordon-Growth-Methode vermeidet man so die Notwendigkeit, eine langfristige Wachstumsrate explizit anzunehmen, die bei kleinen Veränderungen den Terminal Value stark beeinflusst. Allerdings importiert man damit implizit die Marktbewertung und deren Zyklizität in das Modell, was in Hochbewertungsphasen zu einer Überschätzung führen kann.',
  ARRAY['Terminal Value', 'EV/EBITDA-Multiplikator', 'Marktdaten / beobachtbare Vergleichswerte', 'Gordon-Growth-Methode als Alternative', 'Zyklizität / Marktbewertung']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'valuation',
  'exit_multiple',
  'verstaendnis',
  4,
  'Warum kann die Verwendung eines Exit-Multiples, das auf aktuellen Marktmultiples basiert, in einem LBO- oder DCF-Modell zu einer zirkulären Logik führen, und wie sollte ein Analyst damit umgehen?',
  'Das Exit-Multiple basiert typischerweise auf heutigen Handelsmultiples vergleichbarer Unternehmen und wird dann auf das EBITDA am Ende des Prognosezeitraums angewendet – das impliziert jedoch, dass die heutigen Marktbedingungen auch in fünf bis sieben Jahren noch gelten, was eine starke und oft unreflektierte Annahme ist. Die zirkuläre Logik entsteht, weil der heutige Unternehmenswert (z. B. im DCF) selbst durch das Discounting des Terminal Values bestimmt wird, der wiederum auf einem Multiple beruht, das aus heutigen Bewertungen abgeleitet wurde – man bewertet also die Zukunft mit Maßstäben der Gegenwart, die ihrerseits Erwartungen über die Zukunft enthalten. Ein erfahrener Analyst sollte daher das implizite Terminal-Wachstum aus dem Exit-Multiple zurückrechnen (TV = EBITDA × Multiple = FCF / (WACC – g)) und prüfen, ob diese implizite Wachstumsrate ökonomisch plausibel ist. Zusätzlich empfiehlt sich eine Sensitivitätsanalyse über verschiedene Exit-Multiple-Szenarien sowie ein Abgleich mit der Gordon-Growth-Methode als Plausibilitätscheck. Im LBO-Kontext besteht das besondere Risiko, dass ein zu hohes Entry- und Exit-Multiple eine attraktive IRR suggeriert, die rein auf Multiple Expansion basiert und nicht auf operativer Wertschöpfung.',
  ARRAY['Zirkuläre Logik / Gegenwartsmultiples implizieren Zukunftsannahmen', 'Implizites Terminal-Wachstum zurückrechnen', 'Plausibilitätscheck via Gordon-Growth-Modell', 'Sensitivitätsanalyse über Exit-Multiple-Szenarien', 'Multiple Expansion vs. operative Wertschöpfung im LBO']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'dcf',
  'terminal_value',
  'wiedergabe',
  2,
  'Welche zwei Methoden gibt es zur Berechnung des Terminal Value im Rahmen einer DCF-Analyse, und wie lautet die jeweilige Formel?',
  'Im DCF-Modell gibt es zwei gängige Methoden zur Berechnung des Terminal Value. Die erste ist die Gordon-Growth-Methode (Perpetuity Growth Model): TV = FCF_n × (1 + g) / (WACC − g), wobei g die nachhaltige Wachstumsrate und FCF_n der Free Cashflow des letzten Prognosejahres ist. Die zweite Methode ist die Exit-Multiple-Methode: Hier wird der Terminal Value berechnet, indem eine Bewertungskennzahl (z. B. EV/EBITDA) auf die entsprechende Größe des letzten Prognosejahres angewendet wird. Beide Methoden liefern den Wert des Unternehmens jenseits des expliziten Planungshorizonts und müssen anschließend auf den heutigen Zeitpunkt abdiskontiert werden.',
  ARRAY['Gordon-Growth-Methode (Perpetuity Growth Model)', 'Exit-Multiple-Methode', 'Formel: FCF × (1 + g) / (WACC − g)', 'nachhaltige Wachstumsrate (g)', 'Abdiskontierung auf den Barwert']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'dcf',
  'terminal_value',
  'wiedergabe',
  4,
  'Beim Gordon-Growth-Modell für den Terminal Value im DCF gilt die Annahme, dass die ewige Wachstumsrate g kleiner als der WACC sein muss. Was passiert mathematisch und ökonomisch, wenn g den WACC erreicht oder übersteigt, und welche weiteren Restriktionen gelten für g in der Praxis?',
  'Wenn g den WACC erreicht, wird der Nenner (WACC – g) null, sodass der Terminal Value mathematisch gegen unendlich divergiert – das Modell bricht zusammen. Ökonomisch würde ein Unternehmen, das dauerhaft schneller wächst als die Gesamtwirtschaft, irgendwann die gesamte Weltwirtschaft absorbieren, was unrealistisch ist. In der Praxis wird g daher auf das langfristige nominale BIP-Wachstum (typischerweise 1–3 % in entwickelten Märkten) oder die langfristige Inflationsrate gedeckelt. Zusätzlich muss g konsistent mit den impliziten Reinvestitionsannahmen sein: Ein hohes g ohne entsprechende Reinvestitionen (ROIC > WACC) würde den Free Cashflow überschätzen. Analysten sollten daher g und die zugehörige Reinvestitionsrate stets gemeinsam plausibilisieren.',
  ARRAY['Nenner (WACC – g) wird null / TV divergiert gegen unendlich', 'g muss kleiner als nominales BIP-Wachstum / langfristige Inflation sein', 'Ökonomische Absurdität: Unternehmen überholt Gesamtwirtschaft', 'Konsistenz von g mit Reinvestitionsrate und ROIC', 'Praktische Obergrenze: 1–3 % in entwickelten Märkten']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'dcf',
  'terminal_value',
  'anwendung',
  2,
  'Ein Unternehmen erwirtschaftet im letzten Prognosejahr einen Free Cash Flow von 50 Mio. €. Sie gehen von einer ewigen Wachstumsrate von 2 % und einem WACC von 8 % aus. Wie hoch ist der Terminal Value nach der Gordon-Growth-Methode, und wie berechnen Sie ihn?',
  'Der Terminal Value wird mit der Gordon-Growth-Formel berechnet: TV = FCF × (1 + g) / (WACC – g). Mit den gegebenen Werten ergibt sich: TV = 50 Mio. € × 1,02 / (0,08 – 0,02) = 51 Mio. € / 0,06 = 850 Mio. €. Der Terminal Value repräsentiert den Barwert aller zukünftigen Cash Flows jenseits des Prognosezeitraums und muss anschließend noch auf den heutigen Zeitpunkt diskontiert werden. Die Differenz zwischen WACC und Wachstumsrate (der sogenannte „Kapitalisierungszinssatz") ist dabei die entscheidende Größe – eine kleine Veränderung hier hat einen großen Hebel auf das Ergebnis.',
  ARRAY['Gordon-Growth-Formel: FCF × (1 + g) / (WACC – g)', 'Ergebnis: 850 Mio. €', 'Kapitalisierungszinssatz (WACC – g = 6 %)', 'Diskontierung des Terminal Value auf heutigen Zeitpunkt', 'Sensitivität gegenüber Wachstumsrate und WACC']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'dcf',
  'terminal_value',
  'anwendung',
  4,
  'Ein Unternehmen hat im letzten Prognosejahr einen Free Cash Flow von 80 Mio. € erwirtschaftet. Sie verwenden die Gordon-Growth-Methode für den Terminal Value. Der WACC beträgt 9 %, die angenommene ewige Wachstumsrate 3 %. Ein Kollege schlägt vor, stattdessen eine Wachstumsrate von 4 % zu verwenden, da das Unternehmen in einem wachstumsstarken Markt tätig ist. Berechnen Sie den Terminal Value (auf Basis des letzten FCF) für beide Szenarien und erläutern Sie, welches konzeptionelle Problem bei einer Wachstumsrate von 4 % entstehen könnte, wenn der WACC auf 8 % sinkt.',
  'Im Basisszenario (g = 3 %) beträgt der Terminal Value: (80 × 1,03) / (0,09 − 0,03) = 82,4 / 0,06 ≈ 1.373 Mio. €. Im Alternativszenario (g = 4 %) ergibt sich: (80 × 1,04) / (0,09 − 0,04) = 83,2 / 0,05 = 1.664 Mio. €, also eine Steigerung um rund 21 %. Das konzeptionelle Problem zeigt sich, wenn der WACC auf 8 % sinkt und g = 4 % beibehalten wird: Der Spread (WACC − g) schrumpft auf nur 4 %, was den Terminal Value auf 83,2 / 0,04 = 2.080 Mio. € explodieren lässt. Nähert sich g dem WACC an, divergiert die Gordon-Growth-Formel gegen unendlich und verliert jede ökonomische Aussagekraft. Zudem impliziert eine ewige Wachstumsrate oberhalb des langfristigen nominalen BIP-Wachstums, dass das Unternehmen irgendwann die gesamte Volkswirtschaft übertrifft – was strukturell nicht haltbar ist. In solchen Szenarien sollte man den Terminal Value mit einem Exit-Multiple gegenchecken oder die Wachstumsrate konservativ auf das nominale BIP-Niveau deckeln.',
  ARRAY['Gordon-Growth-Formel: TV = FCF × (1+g) / (WACC − g)', 'Spread-Sensitivität: kleiner Nenner führt zu überproportionalem TV-Anstieg', 'Divergenz-Problem: g → WACC lässt TV gegen unendlich gehen', 'Wachstumsrate nicht nachhaltig über nominalem BIP-Wachstum', 'Plausibilitätsprüfung via Exit-Multiple']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'dcf',
  'terminal_value',
  'verstaendnis',
  2,
  'Warum macht der Terminal Value typischerweise den größten Teil des Gesamtunternehmenswertes in einem DCF aus, und welche Implikation hat das für die Verlässlichkeit der Bewertung?',
  'Der Terminal Value repräsentiert in der Regel 60–80 % des gesamten DCF-Wertes, weil die explizite Prognoseperiode meist nur 5–10 Jahre umfasst, während ein Unternehmen theoretisch unendlich lang Cashflows generiert. Da der Terminal Value auf langfristigen Annahmen wie der ewigen Wachstumsrate und dem WACC basiert, ist er besonders sensitiv gegenüber kleinen Veränderungen dieser Parameter. Das bedeutet, dass die Gesamtbewertung stark von schwer prognostizierbaren Langfristannahmen abhängt und damit mit erheblicher Unsicherheit behaftet ist. Analysten sollten daher stets eine Sensitivitätsanalyse für die zentralen Terminal-Value-Treiber durchführen.',
  ARRAY['60–80 % des Gesamtwertes', 'Begrenzte Prognoseperiode (5–10 Jahre)', 'Ewige Wachstumsrate und WACC als Treiber', 'Hohe Sensitivität / Unsicherheit', 'Sensitivitätsanalyse']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'dcf',
  'terminal_value',
  'verstaendnis',
  4,
  'Unter welchen Umständen würde ein Analyst den Exit-Multiple-Ansatz dem Gordon-Growth-Modell für die Terminal-Value-Berechnung vorziehen, und welche fundamentalen Inkonsistenz-Risiken birgt der Exit-Multiple-Ansatz dabei?',
  'Der Exit-Multiple-Ansatz wird bevorzugt, wenn für das Unternehmen vergleichbare Transaktionen oder Peer-Multiples existieren und eine langfristige stabile Wachstumsrate schwer zu schätzen ist – etwa bei zyklischen Branchen oder Unternehmen in Transformationsphasen. Das fundamentale Inkonsistenz-Risiko besteht jedoch darin, dass der verwendete Exit-Multiple implizit eine Wachstumsrate und eine Kapitalrendite enthält, die nicht zwingend mit den im Projektionszeitraum getroffenen Annahmen übereinstimmen. Zudem besteht eine Zirkularität: Wenn die Peer-Multiples selbst auf DCF-Bewertungen basieren, wird Marktbewertung in eine fundamentale Analyse eingebettet, was zu einer doppelten Marktabhängigkeit führt. Ein weiteres Risiko ist, dass aktuelle Marktmultiples konjunkturelle Übertreibungen widerspiegeln können und somit den Terminal Value systematisch über- oder unterschätzen. Methodisch konsistent ist der Ansatz nur, wenn der implizite Terminal-Growth-Rate des Exit-Multiples plausibel mit dem langfristigen Wirtschaftswachstum übereinstimmt.',
  ARRAY['Exit-Multiple vs. Gordon-Growth-Modell', 'Implizite Wachstumsrate im Multiple', 'Zirkularität / Marktabhängigkeit', 'Inkonsistenz mit Projektionsannahmen', 'Impliziter Terminal-Growth-Rate-Check']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'dcf',
  'growth_rate',
  'wiedergabe',
  2,
  'Welche Wachstumsrate wird im DCF-Modell für die Terminal Value-Berechnung verwendet, und wie wird sie typischerweise bestimmt?',
  'Im DCF-Modell wird für die Berechnung des Terminal Values die sogenannte ewige Wachstumsrate (Terminal Growth Rate) verwendet, die das langfristige, nachhaltige Wachstum der freien Cashflows widerspiegelt. Sie wird in der Gordon-Growth-Formel eingesetzt: Terminal Value = FCF × (1 + g) / (WACC – g). Typischerweise orientiert sich diese Rate am langfristigen nominalen BIP-Wachstum des relevanten Marktes, da ein Unternehmen langfristig nicht schneller als die Gesamtwirtschaft wachsen kann. In der Praxis liegt die Terminal Growth Rate häufig zwischen 1 % und 3 % für reife Unternehmen in entwickelten Märkten. Eine Rate oberhalb des langfristigen BIP-Wachstums wäre theoretisch inkonsistent, da das Unternehmen sonst irgendwann die gesamte Volkswirtschaft übertreffen würde.',
  ARRAY['Terminal Growth Rate (ewige Wachstumsrate)', 'Gordon-Growth-Formel: TV = FCF × (1+g) / (WACC – g)', 'Orientierung am langfristigen nominalen BIP-Wachstum', 'Typische Bandbreite 1–3 % für reife Märkte', 'Rate darf WACC nicht übersteigen']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'dcf',
  'growth_rate',
  'wiedergabe',
  4,
  'Welche zwei Methoden gibt es zur Herleitung der ewigen Wachstumsrate (Terminal Growth Rate) im DCF-Modell, und welche konzeptionellen Grenzen muss man bei jeder Methode zwingend beachten?',
  'Die Terminal Growth Rate kann entweder über das nominale BIP-Wachstum (makroökonomischer Ansatz) oder über eine Reinvestitionsrate-basierte Formel (g = ROIC × Reinvestitionsrate) hergeleitet werden. Beim BIP-Ansatz gilt als harte Obergrenze, dass ein Unternehmen langfristig nicht schneller wachsen kann als die Gesamtwirtschaft – andernfalls würde es diese irgendwann vollständig verdrängen. Bei der Reinvestitionsformel muss sichergestellt sein, dass der verwendete ROIC den langfristigen, nachhaltigen Renditewert widerspiegelt und nicht kurzfristig überhöhte Werte enthält, da sonst der Terminal Value systematisch überschätzt wird. Zudem muss die Terminal Growth Rate stets kleiner als der WACC sein, da das Modell sonst mathematisch divergiert und einen unendlichen Unternehmenswert impliziert. In der Praxis liegt die Rate typischerweise zwischen 1,5 % und 3 % für reife Unternehmen in entwickelten Märkten.',
  ARRAY['BIP-Wachstum als Obergrenze', 'g = ROIC × Reinvestitionsrate', 'g < WACC (Konvergenzbedingung)', 'nachhaltiger ROIC', 'Terminal Value Überschätzung']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'dcf',
  'growth_rate',
  'anwendung',
  2,
  'Ein Unternehmen erwirtschaftet im Jahr 1 einen Free Cash Flow von 50 Mio. €. Sie gehen davon aus, dass der FCF in den Jahren 2 bis 5 jährlich um 8 % wächst und danach mit einer ewigen Wachstumsrate von 2 % weiterwächst. Wie hoch ist der FCF in Jahr 5, und welchen Terminal Value erhalten Sie am Ende von Jahr 5, wenn der WACC 10 % beträgt?',
  'Der FCF in Jahr 5 ergibt sich durch viermaliges Aufzinsen des FCF aus Jahr 1 mit 8 %: 50 Mio. € × (1,08)^4 ≈ 68,02 Mio. €. Der Terminal Value am Ende von Jahr 5 wird mit der Gordon-Growth-Formel berechnet: TV = FCF₆ / (WACC – g). Der FCF in Jahr 6 beträgt 68,02 Mio. € × 1,02 ≈ 69,38 Mio. €. Damit ergibt sich ein Terminal Value von 69,38 Mio. € / (10 % – 2 %) = 867,3 Mio. €.',
  ARRAY['FCF Jahr 5: 50 × (1,08)^4 ≈ 68 Mio. €', 'FCF Jahr 6 = FCF Jahr 5 × (1 + ewige Wachstumsrate)', 'Gordon-Growth-Formel: TV = FCF₆ / (WACC – g)', 'Terminal Value ≈ 867 Mio. €', 'WACC minus ewige Wachstumsrate als Nenner']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'dcf',
  'growth_rate',
  'anwendung',
  4,
  'Ein Unternehmen erwirtschaftet im Jahr 1 einen Free Cash Flow von 100 Mio. €. Sie modellieren eine zweistufige DCF-Analyse: In Phase 1 (Jahre 1–5) wächst der FCF mit 12 % p.a., in Phase 2 (Terminal Value) mit 3 % p.a. Der WACC beträgt 9 %. Ein Kollege schlägt vor, die Phase-1-Wachstumsrate auf 15 % zu erhöhen, da das Management optimistischer ist. Welchen konkreten Effekt hat diese Änderung auf den Unternehmenswert, und welche Risiken oder Inkonsistenzen entstehen dabei?',
  'Eine Erhöhung der Phase-1-Wachstumsrate von 12 % auf 15 % steigert die diskontierten FCFs der Jahre 1–5 direkt und erhöht zudem den Basiswert des FCF im Jahr 5, auf dem der Terminal Value aufbaut – der Effekt auf den TV ist daher überproportional groß, da der TV typischerweise 60–80 % des Gesamtwerts ausmacht. Konkret steigt der FCF im Jahr 5 von ca. 176 Mio. € (12 %) auf ca. 201 Mio. € (15 %), was den TV (FCF₅ × (1+g) / (WACC–g)) von ca. 3.080 Mio. € auf ca. 3.518 Mio. € treibt – ein Anstieg von rund 14 % allein beim TV. Die zentrale Inkonsistenz besteht darin, dass eine höhere Phase-1-Wachstumsrate den Übergang zur langfristigen Wachstumsrate von 3 % abrupter macht und implizit höhere Reinvestitionen erfordert, die im FCF-Modell konsistent abgebildet sein müssen. Außerdem sollte geprüft werden, ob ein WACC von 9 % noch angemessen ist, da aggressiveres Wachstum häufig mit höherem operativem und finanziellem Risiko einhergeht. Insgesamt ist die Sensitivität des Modells gegenüber der Phase-1-Wachstumsrate hoch, weshalb eine Szenario- oder Sensitivitätsanalyse zwingend erforderlich ist.',
  ARRAY['Überproportionaler Effekt auf Terminal Value durch höheren FCF-Basiswert in Jahr 5', 'Konkrete Berechnung / Quantifizierung des FCF-Anstiegs in Jahr 5', 'Konsistenz von Wachstum und Reinvestitionen (Reinvestitionsrate)', 'WACC-Anpassung bei höherem Risikoprofil', 'Sensitivitätsanalyse / Szenarioanalyse']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'dcf',
  'growth_rate',
  'verstaendnis',
  2,
  'Warum ist die Wachstumsrate in der Terminal Value-Berechnung eines DCF-Modells typischerweise auf das langfristige BIP-Wachstum begrenzt?',
  'Die Terminal Growth Rate repräsentiert das ewige, nachhaltige Wachstum eines Unternehmens und darf daher langfristig nicht höher sein als das gesamtwirtschaftliche Wachstum – andernfalls würde das Unternehmen irgendwann größer als die gesamte Volkswirtschaft, was ökonomisch nicht möglich ist. In der Praxis orientiert man sich daher am nominalen BIP-Wachstum (reales BIP-Wachstum plus Inflation), typischerweise zwischen 1,5 % und 3 %. Eine zu hohe Terminal Growth Rate hätte zudem einen überproportional großen Einfluss auf den Gesamtunternehmenswert, da der Terminal Value oft 60–80 % des DCF-Wertes ausmacht. Daher ist eine konservative und gut begründete Annahme besonders wichtig, um den Wert nicht zu überschätzen.',
  ARRAY['Terminal Growth Rate', 'BIP-Wachstum als Obergrenze', 'Volkswirtschaft überwachsen nicht möglich', 'Nominales Wachstum (real + Inflation)', 'Terminal Value Anteil am Gesamtwert']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'dcf',
  'growth_rate',
  'verstaendnis',
  4,
  'Warum kann die Verwendung der langfristigen nominalen BIP-Wachstumsrate als Obergrenze für die Terminal Growth Rate in einem DCF zu einer systematischen Unterschätzung des Unternehmenswertes führen, und unter welchen Umständen wäre diese Annahme dennoch zu konservativ?',
  'Die Daumenregel, die Terminal Growth Rate (TGR) auf das nominale BIP-Wachstum zu deckeln, basiert auf der Annahme, dass kein Unternehmen dauerhaft schneller wachsen kann als die Gesamtwirtschaft – andernfalls würde es diese irgendwann vollständig absorbieren. Diese Logik gilt jedoch nur auf aggregierter Ebene: Ein Unternehmen, das in stark wachsenden internationalen Märkten tätig ist oder strukturelle Preissetzungsmacht besitzt, kann sein adressierbares Marktvolumen (TAM) langfristig ausdehnen und damit eine TGR rechtfertigen, die über dem heimischen BIP-Wachstum liegt. Darüber hinaus vernachlässigt die BIP-Obergrenze den Inflation Pass-Through: Unternehmen mit hoher Preismacht können Kostensteigerungen überproportional weitergeben, was das nominale Umsatzwachstum strukturell über das BIP-Niveau hebt. Gleichzeitig führt eine zu niedrig angesetzte TGR in Kombination mit einem hohen WACC zu einer überproportionalen Stauchung des Terminal Value, der typischerweise 60–80 % des Gesamtunternehmenswertes ausmacht, was die Unterschätzung weiter verstärkt. Konservativ bleibt die BIP-Annahme dennoch sinnvoll, wenn das Unternehmen in reifen, schrumpfenden Industrien operiert, hohe Kapitalintensität aufweist oder der Free Cash Flow durch steigende Reinvestitionsquoten strukturell begrenzt ist.',
  ARRAY['Terminal Growth Rate (TGR) vs. BIP-Wachstum', 'Terminal Value als 60–80 % des Unternehmenswertes', 'Preissetzungsmacht / Inflation Pass-Through', 'adressierbarer Markt (TAM) / internationale Expansion', 'Reinvestitionsquote und Free Cash Flow Konversion']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'dcf',
  'beta_unlevering',
  'wiedergabe',
  2,
  'Was versteht man unter dem „Unlevering" eines Betas und wie lautet die dazugehörige Formel?',
  'Beim Unlevering eines Betas wird das beobachtete, verschuldete Beta (Levered Beta) eines Unternehmens um den Einfluss der Kapitalstruktur bereinigt, um das reine operative Risiko – das sogenannte Unlevered Beta (Asset Beta) – zu ermitteln. Dies ist notwendig, weil Unternehmen unterschiedliche Verschuldungsgrade haben und ein direkter Vergleich der Levered Betas verzerrt wäre. Die gängige Formel lautet: β_unlevered = β_levered / (1 + (1 − t) × (D/E)), wobei t der Steuersatz und D/E das Verhältnis von Fremd- zu Eigenkapital ist. Im DCF-Kontext werden die Unlevered Betas vergleichbarer Unternehmen gemittelt und anschließend mit der Zielkapitalstruktur des zu bewertenden Unternehmens wieder „relevered", um den passenden Eigenkapitalkostensatz zu berechnen.',
  ARRAY['Levered Beta', 'Kapitalstruktur / Verschuldungsgrad (D/E)', 'Steuerschild (1 − t)', 'Unlevered Beta / Asset Beta', 'Formel: β_unlevered = β_levered / (1 + (1−t) × D/E)']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'dcf',
  'beta_unlevering',
  'wiedergabe',
  4,
  'Beim Unlevern des Betas eines Vergleichsunternehmens für eine DCF-Analyse – welchen Fehler begehst du, wenn du die Netto-Verschuldung statt der Brutto-Verschuldung verwendest, und in welchen Situationen kann dieser Unterschied besonders gravierend sein?',
  'Die Hamada-Formel und ihre Varianten (z. B. nach Miles-Ezzell oder Practitioners'' Method) verlangen grundsätzlich die Brutto-Verschuldung, da das finanzielle Risiko durch den gesamten Schuldendienst entsteht – nicht durch die Nettogröße. Verwendet man stattdessen die Netto-Verschuldung (Brutto-Schulden minus Cash), unterschätzt man den Verschuldungsgrad (D/E) des Vergleichsunternehmens und erhält ein zu niedrig geunlevertes (Asset-)Beta. Dieses zu niedrige Unlevered Beta führt beim anschließenden Re-Levern auf die Zielkapitalstruktur zu einem ebenfalls zu niedrigen Equity Beta, was den WACC und damit den Diskontierungssatz systematisch unterschätzt. Besonders gravierend ist der Fehler bei Unternehmen mit hohen Cash-Beständen relativ zur Bilanzsumme (z. B. Tech-Konzerne) oder bei stark fremdfinanzierten Targets (LBO-Kontext), wo die Differenz zwischen Brutto- und Nettoverschuldung prozentual sehr groß ist.',
  ARRAY['Brutto-Verschuldung vs. Netto-Verschuldung', 'Hamada-Formel / Unlevered Beta', 'Unterschätzung des Verschuldungsgrads (D/E)', 'zu niedriges Re-Levered Beta / WACC-Unterschätzung', 'Materieller Fehler bei hohem Cash-Bestand oder hohem Leverage']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'dcf',
  'beta_unlevering',
  'anwendung',
  2,
  'Ein Unternehmen hat ein Equity Beta von 1,4, einen Steuersatz von 30 % und eine Debt-to-Equity-Ratio von 0,5. Berechnen Sie das Unlevered Beta dieses Unternehmens.',
  'Um das Unlevered Beta zu berechnen, verwenden wir die Hamada-Formel: β_unlevered = β_levered / (1 + (1 − t) × D/E). Einsetzen der Werte ergibt: β_unlevered = 1,4 / (1 + (1 − 0,30) × 0,5) = 1,4 / (1 + 0,35) = 1,4 / 1,35 ≈ 1,04. Das Unlevered Beta von ca. 1,04 spiegelt das reine Geschäftsrisiko des Unternehmens wider, bereinigt um den Effekt der Kapitalstruktur. Es wird im DCF-Kontext genutzt, um das Beta auf eine neue Zielkapitalstruktur zu relevern.',
  ARRAY['Hamada-Formel', 'Steuereffekt (1 − t)', 'Debt-to-Equity-Ratio', 'Unlevered Beta ≈ 1,04', 'Geschäftsrisiko (operatives Risiko)']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'dcf',
  'beta_unlevering',
  'anwendung',
  4,
  'Sie bewerten ein Unternehmen mittels DCF und haben folgende Vergleichsunternehmen identifiziert: Unternehmen A hat ein Equity Beta von 1,4, eine Eigenkapitalquote von 40 % und einen Steuersatz von 30 %. Unternehmen B hat ein Equity Beta von 1,8, eine Eigenkapitalquote von 60 % und einen Steuersatz von 25 %. Berechnen Sie das durchschnittliche unlevered Beta dieser beiden Peers und erklären Sie, welchen konzeptionellen Fehler ein Analyst begeht, wenn er stattdessen einfach den Durchschnitt der Equity Betas verwendet und diesen direkt als unlevered Beta ansetzt.',
  'Das unlevered Beta von Unternehmen A berechnet sich als 1,4 / (1 + (1 − 0,30) × (60/40)) = 1,4 / 2,05 ≈ 0,683; für Unternehmen B ergibt sich 1,8 / (1 + (1 − 0,25) × (40/60)) = 1,8 / 1,50 = 1,20. Der Durchschnitt der unlevered Betas beträgt somit (0,683 + 1,20) / 2 ≈ 0,94. Der konzeptionelle Fehler beim direkten Mitteln der Equity Betas liegt darin, dass Equity Betas den jeweiligen Financial Leverage der Peers widerspiegeln – unterschiedliche Kapitalstrukturen verzerren den Vergleich erheblich. Indem man zuerst das Leverage herausrechnet (Unlevering) und erst dann mittelt, isoliert man das reine operative Geschäftsrisiko (Asset Beta), das anschließend sauber auf die Zielkapitalstruktur des zu bewertenden Unternehmens re-levered werden kann.',
  ARRAY['Hamada-Formel / Unlevering-Formel: βu = βe / (1 + (1−t) × D/E)', 'Korrekte Berechnung beider unlevered Betas vor der Mittelung', 'Equity Beta enthält Financial Leverage und ist kapitalstrukturabhängig', 'Unlevered Beta repräsentiert reines operatives / Asset-Risiko', 'Anschließendes Re-Levering auf Zielkapitalstruktur des Bewertungsobjekts']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'dcf',
  'beta_unlevering',
  'verstaendnis',
  2,
  'Warum muss man beim DCF-Verfahren den Beta-Wert eines Vergleichsunternehmens „un-levern", bevor man ihn auf das Bewertungsobjekt anwendet?',
  'Der beobachtbare Beta-Wert eines börsennotierten Vergleichsunternehmens ist ein Levered Beta, das sowohl das operative Geschäftsrisiko als auch das Kapitalstrukturrisiko des Vergleichsunternehmens widerspiegelt. Da das Bewertungsobjekt in der Regel eine andere Kapitalstruktur aufweist, würde eine direkte Übernahme des Levered Beta zu einem verzerrten WACC führen. Durch das Un-Levern – typischerweise mit der Hamada-Formel – isoliert man das reine Geschäftsrisiko (Asset Beta bzw. Unlevered Beta). Anschließend wird dieses Unlevered Beta mit der Zielkapitalstruktur des Bewertungsobjekts re-gelevt, um ein passendes Levered Beta für die Eigenkapitalkostenberechnung zu erhalten. So stellt man sicher, dass nur das relevante Risikoprofil in den Diskontierungssatz einfließt.',
  ARRAY['Levered Beta enthält Kapitalstrukturrisiko', 'Un-Levern isoliert das operative Geschäftsrisiko (Asset Beta)', 'Hamada-Formel', 'Re-Levern mit Zielkapitalstruktur des Bewertungsobjekts', 'Verzerrter WACC bei direkter Übernahme']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'dcf',
  'beta_unlevering',
  'verstaendnis',
  4,
  'Beim Unlevering von Beta nach Hamada wird häufig angenommen, dass Fremdkapital ein Beta von null hat. Unter welchen Bedingungen ist diese Annahme problematisch, und wie würde eine Verletzung dieser Annahme den unlevered Beta – und damit Ihren WACC – verzerren?',
  'Die Annahme eines Debt-Beta von null ist nur dann gerechtfertigt, wenn das Unternehmen risikoloses oder quasi-risikoloses Fremdkapital trägt – also bei Investment-Grade-Emittenten mit stabilen Cashflows. Bei hochverschuldeten Unternehmen, Leveraged Buyouts oder Distressed-Situationen weist das Fremdkapital ein signifikant positives Beta auf, da die Gläubiger systematisches Marktrisiko tragen. Ignoriert man ein positives Debt-Beta, wird der unlevered Beta zu niedrig angesetzt: Die Formel βU = βE / (1 + (1−t) × D/E überschätzt den Leverage-Effekt, weil das Risikogewicht des Fremdkapitals nicht herausgerechnet wird. Korrekt müsste man βU = [βE + βD × (1−t) × D/E] / [1 + (1−t) × D/E] verwenden. Ein zu niedriger unlevered Beta führt beim Re-Levering für die Zielkapitalstruktur zu einem zu niedrigen βE und damit zu einem unterschätzten Cost of Equity und WACC, was die Bewertung systematisch nach oben verzerrt.',
  ARRAY['Debt-Beta von null nur bei Investment-Grade gültig', 'positives Debt-Beta bei Distressed/High-Yield-Unternehmen', 'korrekte Hamada-Formel mit Debt-Beta: βU = [βE + βD × (1−t) × D/E] / [1 + (1−t) × D/E]', 'Unterschätzung von βU führt zu zu niedrigem WACC', 'Bewertungsverzerrung nach oben (Overvaluation)']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'lbo',
  'returns_analysis',
  'wiedergabe',
  2,
  'Wie berechnet man den Money-on-Money-Multiple (MoM) und den Internal Rate of Return (IRR) in einem LBO, und was sagen diese beiden Kennzahlen über den Erfolg einer Transaktion aus?',
  'Der Money-on-Money-Multiple (MoM) berechnet sich als Exit-Equity-Erlös geteilt durch das eingesetzte Eigenkapital des Financial Sponsors. Der IRR ist der Diskontierungssatz, bei dem der Nettogegenwartswert aller Cashflows (initiale Investition und Exit-Erlös) gleich null ist – er berücksichtigt damit auch die Haltedauer der Investition. Ein MoM von 2,0x bedeutet beispielsweise, dass der Sponsor sein eingesetztes Kapital verdoppelt hat, sagt aber nichts über den Zeitraum aus. Der IRR hingegen misst die annualisierte Rendite und ist daher das zentrale Erfolgsmaß im Private Equity, da er Zeit und Kapital gemeinsam bewertet. Typische Zielwerte im LBO liegen bei einem MoM von 2,0x–3,0x und einem IRR von 20–25 %.',
  ARRAY['MoM = Exit-Equity / Eingesetztes Eigenkapital', 'IRR = annualisierte Rendite (NPV = 0)', 'MoM ignoriert Haltedauer', 'IRR berücksichtigt Zeit', 'Zielwerte: MoM 2-3x, IRR 20-25%']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'lbo',
  'returns_analysis',
  'wiedergabe',
  4,
  'Welche drei primären Werttreiber bestimmen die Eigenkapitalrendite (MoM) in einem LBO, und wie verändert sich deren relativer Beitrag, wenn der Verschuldungsgrad des Deals sehr hoch ist?',
  'Die drei primären Werttreiber der MoM-Rendite im LBO sind: (1) EBITDA-Wachstum, das den Exit-Unternehmenswert erhöht; (2) Multiple Expansion, also ein höheres EV/EBITDA-Austritts-Multiple gegenüber dem Einstiegs-Multiple; und (3) Schuldenabbau (Debt Paydown), der das Eigenkapital durch Tilgung der Fremdkapitalverbindlichkeiten aus dem Free Cash Flow steigert. Bei sehr hohem Verschuldungsgrad dominiert der Schuldenabbau-Effekt, da ein größerer absoluter Betrag an Fremdkapital getilgt wird und der Equity-Anteil am Gesamtkapital anfänglich klein ist – selbst moderater Debt Paydown führt dann zu überproportionalem Eigenkapitalzuwachs. Gleichzeitig steigt das Risiko, da weniger Puffer für EBITDA-Rückgänge besteht und Covenant-Verletzungen wahrscheinlicher werden.',
  ARRAY['EBITDA-Wachstum', 'Multiple Expansion', 'Debt Paydown / Schuldenabbau', 'Leverage-Effekt bei hohem Verschuldungsgrad', 'Risiko / Covenant']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'lbo',
  'returns_analysis',
  'anwendung',
  2,
  'Ein Private-Equity-Fonds kauft ein Unternehmen für einen Kaufpreis von 100 Mio. € (10x EBITDA bei 10 Mio. € EBITDA) und finanziert den Kauf mit 60 % Fremdkapital. Nach 5 Jahren wird das Unternehmen für 150 Mio. € verkauft, das Fremdkapital wurde vollständig zurückgezahlt. Wie hoch ist der Money-on-Money-Multiple (MoM) und die ungefähre IRR des Investors?',
  'Das eingesetzte Eigenkapital beträgt 40 % von 100 Mio. € = 40 Mio. €. Beim Exit von 150 Mio. € und vollständig zurückgezahltem Fremdkapital fließt der gesamte Verkaufserlös an die Eigenkapitalgeber, also 150 Mio. €. Der MoM berechnet sich als 150 / 40 = 3,75x. Die IRR ergibt sich aus der Gleichung 40 × (1 + IRR)^5 = 150, was einer IRR von ca. 30 % entspricht (Faustformel: 2x in 5 Jahren ≈ 15 %, 3x ≈ 25 %, 4x ≈ 32 %). Ein MoM von 3,75x über 5 Jahre liegt damit bei einer IRR von rund 30 %.',
  ARRAY['Eigenkapitaleinsatz 40 Mio. €', 'MoM = 3,75x', 'IRR ca. 30 %', 'Fremdkapitalhebel (Leverage)', 'Exit-Erlös vollständig an Eigenkapitalgeber']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'lbo',
  'returns_analysis',
  'anwendung',
  4,
  'Ein PE-Fonds kauft ein Unternehmen für einen EV von 500 Mio. € (10x EBITDA, also 50 Mio. € EBITDA) mit 60% Fremdkapital (300 Mio. €) und 40% Eigenkapital (200 Mio. €). Nach 5 Jahren wird das Unternehmen für 600 Mio. € EV verkauft – das EBITDA ist auf 75 Mio. € gewachsen, die Schulden wurden auf 150 Mio. € abgebaut. Der Exit-Multiple beträgt also 8x. Berechnen Sie den MoM und die IRR (Näherung) des Eigenkapitals und erläutern Sie, welcher der drei klassischen Werttreiber im LBO hier dominiert und welcher negativ wirkt.',
  'Der Equity-Erlös beim Exit beträgt 600 Mio. € – 150 Mio. € Schulden = 450 Mio. €, bei einem Eigenkapitaleinsatz von 200 Mio. € ergibt sich ein MoM von 2,25x. Die IRR-Näherung über die Formel (MoM)^(1/5) – 1 liefert ca. 17,6% (2,25^0,2 ≈ 1,176). Die drei klassischen Werttreiber sind EBITDA-Wachstum (von 50 auf 75 Mio. €, +50%), Multiple Expansion/Compression und Debt Paydown. Negativ wirkt hier die Multiple Compression (Einstieg 10x, Exit 8x), die den EV-Anstieg trotz EBITDA-Wachstums dämpft: Ohne Compression wäre der EV 750 Mio. € statt 600 Mio. €. Der dominante positive Treiber ist der Debt Paydown (150 Mio. € Schuldenabbau), der zusammen mit dem EBITDA-Wachstum die Multiple Compression mehr als kompensiert und den MoM auf 2,25x hebt.',
  ARRAY['Equity-Erlös: EV minus Restschuld (450 Mio. €)', 'MoM 2,25x und IRR ~17,6%', 'Debt Paydown als dominanter positiver Werttreiber', 'Multiple Compression (10x → 8x) als negativer Werttreiber', 'EBITDA-Wachstum (+50%) als weiterer positiver Treiber']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'lbo',
  'returns_analysis',
  'verstaendnis',
  2,
  'Welche drei Haupthebel treiben die Eigenkapitalrendite (IRR) in einem LBO, und wie wirken sie sich jeweils auf die Returns aus?',
  'Die drei Haupthebel der IRR in einem LBO sind Financial Leverage, operatives Wachstum (EBITDA-Verbesserung) und Multiple Expansion. Financial Leverage erhöht die Returns, weil Fremdkapital einen Großteil des Kaufpreises finanziert und der Eigenkapitalgeber überproportional vom Wertzuwachs profitiert. Operatives Wachstum – etwa durch Umsatzsteigerung oder Margenerweiterung – erhöht das EBITDA und damit den absoluten Unternehmenswert beim Exit. Multiple Expansion entsteht, wenn das Unternehmen zu einem höheren EV/EBITDA-Multiple verkauft wird als es gekauft wurde, was den Exit-Erlös zusätzlich steigert. In der Praxis ist ein nachhaltiger LBO idealerweise nicht allein auf Multiple Expansion angewiesen, sondern auf echtes operatives Wertschaffen.',
  ARRAY['Financial Leverage', 'EBITDA-Wachstum / operatives Wertschaffen', 'Multiple Expansion', 'Exit-Erlös / Eigenkapitalrendite', 'Überproportionale Partizipation des Eigenkapitals']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'lbo',
  'returns_analysis',
  'verstaendnis',
  4,
  'Ein PE-Fonds kauft ein Unternehmen für einen Einstiegs-EV/EBITDA-Multiple von 10x, finanziert den Kauf mit 60 % Fremdkapital und verkauft das Unternehmen fünf Jahre später zum gleichen Multiple von 10x. Das EBITDA ist in dieser Zeit um 50 % gewachsen. Welche Renditetreiber erklären den erzielten Equity-Return, und wie würde sich die IRR verändern, wenn das Unternehmen stattdessen zu einem Multiple von 8x verkauft würde – obwohl das EBITDA identisch gewachsen ist?',
  'Der Equity-Return wird in diesem Fall ausschließlich durch EBITDA-Wachstum und Schuldenabbau (Debt Paydown) getrieben, da keine Multiple-Expansion stattfindet. Das EBITDA-Wachstum von 50 % erhöht den Exit-EV proportional, während der Schuldenabbau den Equity-Wert überproportional steigert, da der Fremdkapitalanteil sinkt und mehr des Exit-Erlöses den Eigenkapitalgebern zufließt. Beim Exit zu 8x statt 10x entsteht eine Multiple-Kontraktion von 20 %, die den Exit-EV trotz gleichem EBITDA-Wachstum deutlich reduziert – der Equity-Wert schrumpft überproportional, da das Fremdkapital vorrangig bedient wird (sogenannter Leverage-Effekt in beide Richtungen). Die IRR würde spürbar fallen, da der niedrigere Exit-EV den Equity-Erlös nach Schuldentilgung stark komprimiert; je höher der ursprüngliche Leverage, desto größer ist dieser negative Hebeleffekt auf die Eigenkapitalrendite. Dieses Beispiel verdeutlicht, dass Leverage im LBO sowohl Renditen amplifiziert als auch Verluste vergrößert – ein zentraler Trade-off bei der Kapitalstrukturgestaltung.',
  ARRAY['EBITDA-Wachstum als Renditetreiber', 'Debt Paydown / Schuldenabbau', 'Multiple-Kontraktion', 'Leverage-Effekt (Amplifikation in beide Richtungen)', 'Equity-Wert-Kompression bei konstantem Fremdkapital']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'lbo',
  'capital_structure',
  'wiedergabe',
  2,
  'Wie ist die typische Kapitalstruktur in einem Leveraged Buyout aufgebaut, und welche Hauptkomponenten unterscheidet man?',
  'In einem LBO wird das Zielunternehmen überwiegend mit Fremdkapital finanziert, das typischerweise 60–70 % der Gesamtkapitalstruktur ausmacht, während Eigenkapital des Private-Equity-Sponsors die verbleibenden 30–40 % stellt. Das Fremdkapital gliedert sich in vorrangiges besichertes Fremdkapital (Senior Secured Debt), nachrangiges Fremdkapital (Subordinated/Mezzanine Debt) sowie ggf. High-Yield-Anleihen. Senior Debt hat die höchste Priorität bei Zins- und Tilgungszahlungen sowie im Insolvenzfall, während Mezzanine-Kapital eine höhere Verzinsung trägt, um das größere Ausfallrisiko zu kompensieren. Das Eigenkapital des Sponsors steht in der Kapitalstruktur an letzter Stelle (Residualanspruch), bietet aber das größte Renditepotenzial durch den Leverage-Effekt.',
  ARRAY['Senior Secured Debt (vorrangiges Fremdkapital)', 'Mezzanine / Nachrangkapital', 'Eigenkapital des PE-Sponsors (30–40 %)', 'Fremdkapitalanteil ca. 60–70 %', 'Priorität der Ansprüche (Wasserfallprinzip)']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'lbo',
  'capital_structure',
  'wiedergabe',
  4,
  'Welche Tranchen bilden typischerweise die Kapitalstruktur eines LBOs, und wie unterscheiden sich diese hinsichtlich Rang, Verzinsung und Covenant-Intensität?',
  'Die LBO-Kapitalstruktur besteht typischerweise aus mehreren Schichten: Senior Secured Debt (Term Loan A/B, RCF) steht im Rang ganz oben, wird zu variablen Zinsen (z. B. SOFR + Spread) vergeben und ist mit den strengsten Covenants (Maintenance Covenants) versehen. Darunter folgen Second Lien oder Senior Unsecured Notes (High-Yield-Bonds), die höhere Kupons tragen und meist nur Incurrence Covenants aufweisen. Mezzanine-Kapital oder PIK-Instrumente stehen noch tiefer im Rang, bieten dem Kreditgeber höhere Renditen (teils durch PIK-Zinsen), sind aber im Insolvenzfall nachrangig gegenüber allen Senior-Tranchen. Das Eigenkapital des Sponsors bildet die unterste Schicht (First Loss), trägt das höchste Risiko, profitiert aber überproportional vom Upside durch den Leverage-Effekt. Je tiefer die Tranche im Rang, desto höher die geforderte Rendite und desto geringer die Covenant-Dichte, da die Gläubiger das erhöhte Risiko durch Rendite statt Kontrolle kompensieren.',
  ARRAY['Senior Secured / Term Loan A & B', 'Nachrangigkeit und Risikoaufschlag (Spread)', 'Maintenance vs. Incurrence Covenants', 'PIK / Mezzanine', 'Eigenkapital als First Loss / Leverage-Effekt']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'lbo',
  'capital_structure',
  'anwendung',
  2,
  'Ein Private-Equity-Fonds kauft ein Unternehmen mit einem Enterprise Value von 500 Mio. € bei einem Entry-Multiple von 10x EBITDA. Die Kapitalstruktur beim Closing besteht zu 60 % aus Fremdkapital und zu 40 % aus Eigenkapital. Wie hoch sind der Fremdkapitalbetrag und der Eigenkapitaleinsatz des Sponsors in absoluten Zahlen?',
  'Der Enterprise Value beträgt 500 Mio. €, was einem EBITDA von 50 Mio. € entspricht (500 / 10x). Das Fremdkapital beläuft sich auf 60 % × 500 Mio. € = 300 Mio. €, das Eigenkapital des Sponsors auf 40 % × 500 Mio. € = 200 Mio. €. Der Verschuldungsgrad (Debt-to-EBITDA) liegt damit bei 6,0x, was einem typischen LBO-Einstiegsniveau entspricht. Der Sponsor setzt also 200 Mio. € eigenes Kapital ein und finanziert den Rest über Fremdkapital, um die Eigenkapitalrendite durch den Leverage-Effekt zu steigern.',
  ARRAY['Fremdkapital 300 Mio. € (60 %)', 'Eigenkapital 200 Mio. € (40 %)', 'Debt-to-EBITDA 6,0x', 'Leverage-Effekt / Eigenkapitalrendite', 'EBITDA 50 Mio. €']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'lbo',
  'capital_structure',
  'anwendung',
  4,
  'Ein PE-Fonds erwirbt ein Unternehmen für einen EV von 500 Mio. € (8x EBITDA, EBITDA = 62,5 Mio. €) und finanziert den Kauf mit 300 Mio. € Debt (aufgeteilt in 200 Mio. € Senior Secured Term Loan B zu 6% p.a. und 100 Mio. € Mezzanine zu 12% p.a.) sowie 200 Mio. € Equity. Nach 5 Jahren beträgt der Restschuldenstand des TLB 120 Mio. €, der Mezzanine ist vollständig getilgt, und das EBITDA ist auf 90 Mio. € gewachsen. Der Exit erfolgt zu 9x EBITDA. Wie hoch ist der MOIC für den Equity-Investor, und welcher Effekt dominiert die Wertschaffung – Multiple Expansion, Debt Paydown oder EBITDA-Wachstum? Zeigen Sie Ihre Rechnung.',
  'Der Exit-EV beträgt 90 Mio. € × 9 = 810 Mio. €; nach Abzug der verbleibenden Nettoschulden von 120 Mio. € ergibt sich ein Equity Value von 690 Mio. €, was einem MOIC von 690 / 200 = 3,45x entspricht. Die drei Werttreiber lassen sich isolieren: EBITDA-Wachstum trägt (90 − 62,5) × 8 = 220 Mio. € bei, Multiple Expansion trägt 90 × (9 − 8) = 90 Mio. € bei, und Debt Paydown (300 − 120 = 180 Mio. € Tilgung) trägt 180 Mio. € bei. Das EBITDA-Wachstum ist mit 220 Mio. € der dominante Werttreiber, gefolgt von Debt Paydown (180 Mio. €) und Multiple Expansion (90 Mio. €). In einem realen LBO-Kontext ist es wichtig zu beachten, dass Mezzanine-Zinsen oft PIK-Anteile enthalten können, was die tatsächliche Schuldenlast erhöhen würde; hier wurde vereinfachend von vollständiger Cash-Tilgung ausgegangen.',
  ARRAY['Exit Equity Value = Exit-EV minus Restschuld', 'MOIC-Berechnung (Exit Equity / Entry Equity)', 'Drei Werttreiber: EBITDA-Wachstum, Debt Paydown, Multiple Expansion', 'Isolierung und Quantifizierung der einzelnen Werttreiber', 'EBITDA-Wachstum als dominanter Treiber']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'lbo',
  'capital_structure',
  'verstaendnis',
  2,
  'Warum wird in einem LBO typischerweise eine Mischung aus verschiedenen Fremdkapitalinstrumenten (z. B. Senior Debt, Mezzanine, PIK) verwendet und nicht einfach nur eine einzige Schuldentranche?',
  'In einem LBO wird die Kapitalstruktur bewusst in mehrere Tranchen aufgeteilt, um die Gesamtfinanzierungskosten zu minimieren und gleichzeitig das maximale Fremdkapitalvolumen auszuschöpfen. Senior Debt ist am günstigsten, da es durch Vermögenswerte besichert ist und vorrangig bedient wird – allerdings ist das verfügbare Volumen begrenzt. Mezzanine-Kapital und PIK-Instrumente füllen die Lücke zwischen Senior Debt und Eigenkapital, akzeptieren ein höheres Risiko und verlangen dafür eine höhere Rendite. Durch diese Schichtung (sog. „Tranching") kann der Private-Equity-Sponsor den Eigenkapitaleinsatz minimieren und damit die potenzielle Eigenkapitalrendite (IRR) maximieren. Jede Tranche spricht zudem unterschiedliche Investorengruppen mit unterschiedlichen Risiko-Rendite-Präferenzen an, was die Platzierbarkeit der Gesamtfinanzierung erhöht.',
  ARRAY['Tranching / Schichtung der Kapitalstruktur', 'Finanzierungskosten minimieren', 'Senior Debt – besichert, günstig, begrenzt', 'Mezzanine / PIK – höheres Risiko, höhere Rendite', 'Eigenkapitaleinsatz minimieren / IRR maximieren']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'lbo',
  'capital_structure',
  'verstaendnis',
  4,
  'Warum kann eine aggressivere Kapitalstruktur mit höherem Verschuldungsgrad in einem LBO unter bestimmten Umständen den Eigenkapitalwert für den Sponsor *verringern* statt erhöhen, obwohl der Leverage-Effekt theoretisch die Eigenkapitalrendite steigert?',
  'Obwohl höherer Leverage die Eigenkapitalrendite durch den Hebel-Effekt theoretisch steigert, kann er den Eigenkapitalwert zerstören, wenn die Zinskosten den freien Cashflow übersteigen und das Unternehmen in finanzielle Notlage gerät. In einem Distress-Szenario entstehen direkte Kosten (Restrukturierungsgebühren, Rechtskosten) und indirekte Kosten (Kundenverlust, Lieferantenkonditionen verschlechtern sich, Management-Ablenkung), die den Unternehmenswert substanziell mindern. Darüber hinaus schränkt ein hoher Schuldendienst die operative Flexibilität ein – notwendige Investitionen (Capex, M&A) können nicht getätigt werden, was das Wachstum und damit den Exit-Multiple beeinträchtigt. Der optimale Verschuldungsgrad liegt daher nicht am Maximum, sondern wo der Grenznutzen des Steuervorteils (Tax Shield) gleich den Grenzkosten der finanziellen Notlage ist – ein klassischer Trade-off aus der Kapitalstrukturtheorie. Zudem können Covenant-Verletzungen dem Kreditgeber Kontrolle übertragen und den Sponsor zwingen, zu ungünstigen Konditionen Eigenkapital nachzuschießen oder Assets zu verkaufen.',
  ARRAY['Financial Distress Costs (direkt & indirekt)', 'Tax Shield vs. Distress-Kosten Trade-off', 'Cashflow-Deckung / Debt Service Coverage', 'Operative Flexibilität / Investitionsbeschränkung', 'Covenant-Verletzung und Kontrollverlust']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'lbo',
  'exit_scenarios',
  'wiedergabe',
  2,
  'Welche typischen Exit-Wege stehen einem Private-Equity-Investor nach einem Leveraged Buyout zur Verfügung?',
  'Nach einem LBO hat der Private-Equity-Investor typischerweise drei klassische Exit-Optionen: Erstens der Trade Sale, bei dem das Unternehmen an einen strategischen Käufer verkauft wird. Zweitens der Secondary Buyout (SBO), bei dem ein anderer Finanzinvestor das Unternehmen übernimmt. Drittens der Börsengang (IPO), bei dem das Unternehmen an die Börse gebracht und die Anteile an öffentliche Investoren verkauft werden. Der gewählte Exit-Weg hängt von Marktbedingungen, der Unternehmensgröße und dem angestrebten Verkaufserlös ab, da er maßgeblich die realisierte Rendite (IRR und MOIC) des Fonds bestimmt.',
  ARRAY['Trade Sale', 'Secondary Buyout (SBO)', 'IPO (Börsengang)', 'IRR / MOIC (Rendite)', 'Marktbedingungen']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'lbo',
  'exit_scenarios',
  'wiedergabe',
  4,
  'Welche Exit-Multiplen werden im LBO-Modell typischerweise angesetzt, und welcher konzeptionelle Fehler entsteht, wenn man den Entry-Multiple unreflektiert als Exit-Multiple übernimmt?',
  'Im LBO-Modell wird der Exit-Multiple üblicherweise als EV/EBITDA-Multiple angesetzt, der auf Basis von Peer-Group-Transaktionen, öffentlichen Vergleichsunternehmen oder einem konservativen Abschlag auf den Entry-Multiple geschätzt wird. Der konzeptionelle Fehler beim unreflektierten Gleichsetzen von Entry- und Exit-Multiple liegt im sogenannten „Multiple Expansion"-Zirkelschluss: Man unterstellt implizit, dass das Marktumfeld und die Bewertungsniveaus zum Exitpunkt identisch sind wie beim Einstieg, was in der Praxis selten zutrifft. Darüber hinaus ignoriert diese Annahme, dass sich das Risikoprofil des Unternehmens durch den Leverage, mögliche operative Veränderungen oder Branchenzyklen verändert haben kann. Ein konservativer Analyst setzt den Exit-Multiple daher bewusst niedriger als den Entry-Multiple an, um keine künstliche Rendite durch Multiple Expansion zu erzeugen. Die IRR sollte primär durch EBITDA-Wachstum und Schuldenabbau (Debt Paydown) getrieben sein, nicht durch Bewertungsarbitrage.',
  ARRAY['EV/EBITDA Exit-Multiple', 'Multiple Expansion Zirkelschluss', 'Entry-Multiple ≠ Exit-Multiple (konservativer Abschlag)', 'IRR-Treiber: EBITDA-Wachstum und Debt Paydown', 'Marktumfeld / Bewertungsniveau zum Exitpunkt']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'lbo',
  'exit_scenarios',
  'anwendung',
  2,
  'Ein Private-Equity-Fonds hat ein Unternehmen vor 5 Jahren für einen Enterprise Value von 100 Mio. € gekauft und dabei 60 Mio. € Fremdkapital eingesetzt. Heute beträgt der Enterprise Value 180 Mio. € und die verbleibende Verschuldung liegt bei 20 Mio. €. Wie hoch ist der Money-on-Money-Multiple (MoM) auf das eingesetzte Eigenkapital, und wie interpretieren Sie diesen Exit?',
  'Beim Einstieg betrug das eingesetzte Eigenkapital 100 Mio. € minus 60 Mio. € Fremdkapital, also 40 Mio. €. Beim Exit ergibt sich ein Eigenkapitalwert von 180 Mio. € minus 20 Mio. € verbleibender Schulden, also 160 Mio. €. Der MoM beträgt damit 160 / 40 = 4,0x. Über einen Zeitraum von 5 Jahren entspricht das einem IRR von ungefähr 32 %, was einem sehr guten LBO-Exit entspricht. Der Wertzuwachs resultiert sowohl aus dem EBITDA-Wachstum bzw. Multiple Expansion als auch aus der Schuldenrückzahlung (Debt Paydown) von 40 Mio. €.',
  ARRAY['Eigenkapitaleinsatz (Equity Check) 40 Mio. €', 'Eigenkapitalwert beim Exit 160 Mio. €', 'MoM 4,0x', 'IRR ca. 32 %', 'Debt Paydown als Werttreiber']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'lbo',
  'exit_scenarios',
  'anwendung',
  4,
  'Ein PE-Fonds hat ein Unternehmen vor 5 Jahren für 500 Mio. € (10x EBITDA, 50 Mio. € EBITDA) gekauft und mit 60% Fremdkapital finanziert. Heute beträgt das EBITDA 80 Mio. €, die Nettoverschuldung wurde auf 120 Mio. € abgebaut, und der Fonds erwägt einen Exit via strategischem Verkauf (12x EBITDA) oder IPO (14x EBITDA, aber 180-Tage-Lock-up und 15% Bewertungsabschlag auf den platzierten Anteil). Welchen Exit-Kanal würden Sie empfehlen, und wie hoch ist der ungefähre MoM (Multiple on Money) in beiden Szenarien?',
  'Beim strategischen Verkauf ergibt sich ein Enterprise Value von 960 Mio. € (12x × 80 Mio. €), abzüglich Nettoverschuldung von 120 Mio. € ein Equity Value von 840 Mio. €; bei einem Eigenkapitaleinsatz von 200 Mio. € (40% von 500 Mio. €) entspricht das einem MoM von ca. 4,2x. Beim IPO beträgt der EV 1.120 Mio. € (14x × 80 Mio. €), Equity Value 1.000 Mio. €, jedoch reduziert der 15%ige Platzierungsabschlag den effektiv realisierten Erlös auf ca. 850 Mio. €, was einem MoM von ca. 4,25x entspricht – also nur marginal besser. Der entscheidende Trade-off liegt im Liquiditätsrisiko: Beim IPO ist der Fonds durch den 180-Tage-Lock-up exponiert gegenüber Marktvolatilität, möglichen Bewertungskorrekturen und kann nicht sofort vollständig exitieren, was den IRR belastet. Ein strategischer Verkauf bietet Sicherheit durch Clean Exit, sofortige Liquidität und keine Marktrisiken, was bei vergleichbarem MoM klar zu bevorzugen ist – es sei denn, der Fonds erwartet eine signifikante Neubewertung nach Lock-up-Ablauf.',
  ARRAY['MoM-Berechnung (Equity Value minus Nettoverschuldung / Eigenkapitaleinsatz)', 'IPO-Bewertungsabschlag (Discount) reduziert effektiven Erlös', 'Lock-up-Periode und Marktrisiko als IRR-Belastung', 'Clean Exit vs. Liquiditätsrisiko Trade-off', 'Strategischer Käufer zahlt Kontrollprämie (höheres Multiple möglich)']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'lbo',
  'exit_scenarios',
  'verstaendnis',
  2,
  'Welche typischen Exit-Optionen stehen einem Private-Equity-Investor nach einem Leveraged Buyout zur Verfügung, und welche Faktoren beeinflussen die Wahl des Exit-Weges?',
  'Nach einem LBO stehen dem PE-Investor grundsätzlich drei Exit-Optionen zur Verfügung: der Verkauf an einen strategischen Käufer (Trade Sale), der Verkauf an einen anderen Finanzinvestor (Secondary Buyout) sowie der Börsengang (IPO). Die Wahl hängt von mehreren Faktoren ab: Bei einem Trade Sale erzielt man oft die höchste Bewertung, da strategische Käufer Synergien einpreisen können; ein IPO bietet Liquidität, erfordert aber günstige Kapitalmarktbedingungen und eine gewisse Unternehmensgröße. Ein Secondary Buyout ist häufig die schnellste Option, wird aber von Investoren kritisch betrachtet, da die Frage entsteht, welches weitere Wertsteigerungspotenzial noch vorhanden ist. Entscheidend sind zudem das Marktumfeld, die Reife des Unternehmens, die Haltedauer sowie die Renditeziele des Fonds.',
  ARRAY['Trade Sale', 'Secondary Buyout', 'IPO (Börsengang)', 'Synergien / strategische Prämie', 'Marktumfeld / Kapitalmarktbedingungen']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'lbo',
  'exit_scenarios',
  'verstaendnis',
  4,
  'Ein PE-Fonds hat ein Portfolio-Unternehmen per LBO erworben und erwägt nach fünf Jahren einen Secondary Buyout (SBO) als Exit-Route. Unter welchen Bedingungen ist ein SBO gegenüber einem strategischen Verkauf oder einem IPO vorzuziehen, und welche strukturellen Nachteile bringt ein SBO für die Rendite des verkaufenden Fonds mit sich?',
  'Ein SBO ist dann sinnvoll, wenn das Unternehmen noch erhebliches Wertsteigerungspotenzial aufweist, das ein strategischer Käufer nicht vollständig bezahlen würde, oder wenn die Kapitalmärkte für einen IPO ungünstig sind. Allerdings ist die Käuferbasis bei einem SBO auf finanzielle Investoren beschränkt, was den Wettbewerb und damit den erzielbaren Kaufpreis im Vergleich zu einem strategischen Käufer, der Synergien einpreisen kann, strukturell limitiert. Ein weiterer Nachteil ist das sogenannte „Leverage Recycling"-Problem: Da das Unternehmen bereits durch einen LBO optimiert wurde, sind die offensichtlichsten operativen und finanziellen Hebel ausgeschöpft, was den neuen Käufer zwingt, eine höhere Einstiegsbewertung mit weniger klaren Werttreibern zu rechtfertigen. Für den verkaufenden Fonds bedeutet dies, dass er zwar Liquidität erzielt, aber oft einen Bewertungsabschlag gegenüber einem strategischen Exit akzeptieren muss, was die IRR-Maximierung beeinträchtigt. Zudem signalisiert ein SBO dem Markt potenziell, dass kein strategischer Käufer bereit war, einen Aufpreis zu zahlen, was Reputationsrisiken für den Fonds birgt.',
  ARRAY['Secondary Buyout (SBO) vs. strategischer Käufer (Synergieprämie)', 'Beschränkte Käuferbasis / kein Synergiepotenzial', 'Leverage Recycling / ausgeschöpfte Werttreiber', 'IRR-Implikationen / Bewertungsabschlag', 'Marktsignal / Reputationsrisiko']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'markets',
  'news_rationale',
  'wiedergabe',
  2,
  'Was versteht man unter der Zinsstrukturkurve (Yield Curve) und was signalisiert eine inverse Zinsstrukturkurve typischerweise für die Konjunktur?',
  'Die Zinsstrukturkurve zeigt den Zusammenhang zwischen der Restlaufzeit von Anleihen und deren Rendite. Normalerweise ist sie positiv geneigt, da Investoren für längere Laufzeiten eine höhere Rendite als Ausgleich für das größere Risiko verlangen. Eine inverse Zinsstrukturkurve entsteht, wenn kurzfristige Zinsen über den langfristigen Zinsen liegen. Dies gilt historisch als zuverlässiger Frühindikator für eine bevorstehende Rezession, da der Markt sinkende Leitzinsen in der Zukunft – als Reaktion auf eine wirtschaftliche Abschwächung – einpreist. In der Praxis wird häufig die Differenz zwischen der 10-jährigen und der 2-jährigen US-Staatsanleihe (10Y-2Y-Spread) als Maßstab herangezogen.',
  ARRAY['Rendite vs. Laufzeit', 'normale vs. inverse Kurve', 'Rezessionsindikator', 'kurzfristige Zinsen über langfristigen', '10Y-2Y-Spread']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'markets',
  'news_rationale',
  'wiedergabe',
  4,
  'Die EZB hat überraschend signalisiert, die Reinvestitionen im Rahmen des APP früher als erwartet zu beenden. Erkläre, über welche geldpolitischen Transmissionskanäle diese Bilanzverkürzung auf die Realwirtschaft wirkt und wo die entscheidenden Wirkungsgrenzen liegen.',
  'Die Bilanzverkürzung wirkt primär über den Portfolio-Balance-Kanal: Wenn die EZB keine fälligen Anleihen mehr reinvestiert, steigt das Angebot an Staatsanleihen am Markt, was deren Kurse drückt und die Renditen erhöht – dies verteuert die Refinanzierung für Staaten und Unternehmen. Gleichzeitig wirkt der Signalkanal, da Marktteilnehmer eine restriktivere Haltung der Notenbank einpreisen und die Zinserwartungen nach oben anpassen. Über den Kreditkanal steigen die Finanzierungskosten der Banken, was die Kreditvergabe an Haushalte und Unternehmen dämpft und damit Konsum und Investitionen bremst. Die entscheidende Wirkungsgrenze liegt jedoch darin, dass Quantitative Tightening (QT) asymmetrisch wirkt: Die Wirkung ist empirisch schwächer und unsicherer als die des Quantitative Easing (QE), da Liquiditätspräferenzen und Marktfragmentierung im Euroraum die Transmission verzerren können. Zudem besteht das Risiko einer ungewollten Fragmentierung, falls Spreads zwischen Peripherie- und Kernländern stark auseinanderlaufen, was das TPI (Transmission Protection Instrument) der EZB aktivieren könnte.',
  ARRAY['Portfolio-Balance-Kanal', 'Quantitative Tightening (QT) Asymmetrie', 'Kreditkanal / Refinanzierungskosten', 'Signalkanal / Zinserwartungen', 'Fragmentierungsrisiko / TPI']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'markets',
  'news_rationale',
  'anwendung',
  2,
  'Die EZB hat heute überraschend die Leitzinsen um 50 Basispunkte angehoben. Eine 10-jährige deutsche Bundesanleihe mit einem Kupon von 2 % und einem aktuellen Kurs von 100 notiert nun neu bei einem Yield von 2,5 %. Wie verändert sich der Kurs der Anleihe näherungsweise, und was erklärt diese Bewegung?',
  'Steigen die Marktzinsen, fallen die Kurse bestehender Anleihen, da deren fixer Kupon relativ unattraktiver wird – Zins und Kurs bewegen sich invers. Die Duration einer 10-jährigen Anleihe liegt näherungsweise bei rund 8–9 Jahren; mit der Formel ΔP ≈ −Duration × ΔYield ergibt sich ein Kursrückgang von etwa 4–4,5 % (z. B. −8,5 × 0,005 ≈ −4,25 %). Der Kurs fällt also von 100 auf rund 95,75. Die EZB-Zinserhöhung signalisiert eine restriktivere Geldpolitik, was die risikofreie Rendite anhebt und Anleihekurse am gesamten Markt unter Druck setzt.',
  ARRAY['Inverse Zins-Kurs-Beziehung', 'Duration als Sensitivitätsmaß', 'Näherungsformel ΔP ≈ −Duration × ΔYield', 'Kursrückgang ca. 4–4,5 %', 'Restriktive Geldpolitik / EZB-Signal']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'markets',
  'news_rationale',
  'anwendung',
  4,
  'Die EZB hat überraschend signalisiert, die Zinsen länger als erwartet auf dem aktuellen Niveau zu halten. Ein Investor hält eine 10-jährige deutsche Bundesanleihe mit einem Kupon von 2 % und einem aktuellen Marktzins von 3 %. Die Modified Duration der Anleihe beträgt 8,5. Wie verändert sich der Preis der Anleihe näherungsweise, wenn der Markt infolge der EZB-Ankündigung die Zinserwartungen um 25 Basispunkte nach oben revidiert – und welche zusätzliche Risikokomponente sollte der Investor bei einem längeren Hochzinsumfeld beachten?',
  'Ein Anstieg der Zinserwartungen um 25 Basispunkte führt zu einer näherungsweisen Preisänderung von −(Modified Duration × ΔYield) = −(8,5 × 0,0025) = −2,125 %. Bei einem angenommenen aktuellen Kurs von rund 93,5 (Anleihe notiert unter Par, da Kupon < Marktzins) entspricht das einem Kursverlust von ca. 2 Punkten. Zusätzlich muss der Investor das Konvexitätsrisiko berücksichtigen: Die Duration-Näherung überschätzt den tatsächlichen Kursverlust leicht, da positive Konvexität den Rückgang etwas abfedert. Im längeren Hochzinsumfeld entsteht außerdem ein Reinvestitionsrisiko, da fällige Kupons zwar zu höheren Sätzen reinvestiert werden können, der Kursrückgang jedoch den Gesamtertrag (Total Return) bei vorzeitigem Verkauf belastet. Der Investor sollte daher seinen Anlagehorizont mit der Duration abgleichen, um Kurs- und Reinvestitionsrisiko gegeneinander auszubalancieren.',
  ARRAY['Modified Duration', 'Preisänderung −2,125 %', 'Konvexität', 'Reinvestitionsrisiko', 'Total Return / Anlagehorizont']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'markets',
  'news_rationale',
  'verstaendnis',
  2,
  'Die Europäische Zentralbank hat überraschend eine Zinssenkung angekündigt. Warum reagieren die Anleihemärkte typischerweise mit steigenden Kursen auf eine solche Nachricht?',
  'Wenn die EZB die Zinsen senkt, sinken die Marktzinsen, was direkt den Diskontierungssatz für zukünftige Cashflows reduziert. Da Anleihen feste Kuponzahlungen haben, steigt ihr Barwert, wenn der Diskontierungssatz fällt – Anleihekurse und Renditen bewegen sich also invers zueinander. Zudem werden bereits im Umlauf befindliche Anleihen mit höheren Kupons im Vergleich zu neu emittierten Anleihen attraktiver, was die Nachfrage und damit den Kurs treibt. Schließlich signalisiert eine Zinssenkung oft ein schwächeres Wirtschaftsumfeld, was Investoren in sichere Anlagen wie Staatsanleihen treibt und den Preisanstieg zusätzlich verstärkt.',
  ARRAY['Inverse Beziehung zwischen Anleihekurs und Rendite', 'Diskontierungssatz / Barwert', 'Feste Kuponzahlungen werden attraktiver', 'Nachfrage nach sicheren Anlagen (Safe Haven)']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'markets',
  'news_rationale',
  'verstaendnis',
  4,
  'Die EZB hat zuletzt die Leitzinsen gesenkt, obwohl die Kerninflation im Euroraum noch deutlich über dem 2%-Ziel liegt. Welche Risiken und Trade-offs geht die EZB mit dieser Entscheidung ein, und unter welchen Bedingungen wäre eine solche Lockerung trotzdem gerechtfertigt?',
  'Die EZB steht vor einem klassischen Trade-off zwischen Preisstabilität und Wachstumsstabilisierung: Eine Zinssenkung bei noch erhöhter Kerninflation riskiert, Inflationserwartungen zu de-ankern und die Glaubwürdigkeit des Mandats zu beschädigen. Gerechtfertigt wäre die Lockerung, wenn die Gesamtinflation bereits deutlich fällt, die Konjunktur stark abkühlt und Zweitrundeneffekte – etwa durch nachlassenden Lohndruck – begrenzt erscheinen. Ein weiterer Rechtfertigungsgrund liegt in der Transmission: Wenn restriktive Finanzierungsbedingungen die Kreditvergabe bereits stark einschränken, kann die Realwirtschaft überproportional belastet werden, ohne dass weitere Zinserhöhungen den Inflationspfad wesentlich beschleunigen. Kritisch bleibt jedoch, dass eine verfrühte Lockerung die „Last Mile" der Disinflation erschwert, da Dienstleistungsinflation und Lohnwachstum träge reagieren. Die EZB muss daher datenabhängig kommunizieren und den Forward Guidance-Rahmen nutzen, um Markterwartungen zu steuern, ohne die Inflationsbekämpfung zu untergraben.',
  ARRAY['Preisstabilität vs. Wachstumsstabilisierung (Trade-off)', 'De-Ankerung der Inflationserwartungen', 'Zweitrundeneffekte / Lohndruck', 'Last Mile Disinflation', 'Datenabhängigkeit / Forward Guidance']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'markets',
  'rates_impact',
  'wiedergabe',
  2,
  'Wie wirkt sich ein Anstieg des allgemeinen Zinsniveaus auf die Kurse bestehender Anleihen aus, und warum?',
  'Wenn das allgemeine Zinsniveau steigt, fallen die Kurse bestehender Anleihen – und umgekehrt. Der Grund liegt darin, dass die fixen Kuponzahlungen einer bestehenden Anleihe im Vergleich zu neu emittierten Anleihen mit höheren Kupons weniger attraktiv werden. Um die Anleihe am Markt verkäuflich zu machen, muss ihr Kurs sinken, bis ihre Rendite (Yield) dem neuen Marktzinsniveau entspricht. Dieser inverse Zusammenhang zwischen Zinsen und Anleihekursen ist eine der grundlegendsten Beziehungen im Fixed-Income-Bereich. Je länger die Restlaufzeit einer Anleihe, desto stärker reagiert ihr Kurs auf Zinsänderungen (höhere Duration).',
  ARRAY['Inverser Zusammenhang (Zinsen steigen → Kurse fallen)', 'Fixe Kuponzahlungen werden relativ unattraktiver', 'Rendite (Yield) muss dem Marktzinsniveau entsprechen', 'Duration: längere Laufzeit = stärkere Kursreaktion']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'markets',
  'rates_impact',
  'wiedergabe',
  4,
  'Erkläre den genauen Transmissionsmechanismus, über den eine unerwartete Leitzinserhöhung der EZB den Kurs eines langlaufenden Staatsanleihen-Futures beeinflusst – und warum die Reaktion des Futures stärker ausfällt als die einer kurzlaufenden Anleihe.',
  'Eine unerwartete Leitzinserhöhung treibt die Marktzinsen entlang der gesamten Zinsstrukturkurve nach oben, wobei der Anstieg am langen Ende durch veränderte Inflations- und Wachstumserwartungen verstärkt wird. Da der Kurs einer Anleihe dem Barwert aller zukünftigen Cashflows entspricht, führt ein höherer Diskontierungssatz zu einem Kursrückgang – der Futures-Kurs fällt entsprechend. Der entscheidende Unterschied zur kurzlaufenden Anleihe liegt in der Duration: Eine langlaufende Anleihe hat eine deutlich höhere Modified Duration, sodass dieselbe Zinsänderung (Δy) einen proportional größeren Kursrückgang (ΔP ≈ –MD × Δy × P) bewirkt. Zusätzlich verstärkt der Konvexitätseffekt die Asymmetrie, ist bei steigenden Kursen vorteilhaft und bei fallenden Kursen nachteilig, spielt aber bei kleinen Zinsschocks eine untergeordnete Rolle. Der Futures-Kurs reflektiert zudem den Forward-Preis der Anleihe und reagiert daher nahezu eins zu eins mit dem Kassapreis, abzüglich des Cost-of-Carry-Effekts.',
  ARRAY['Modified Duration', 'Barwert / Diskontierungssatz', 'ΔP ≈ –MD × Δy × P', 'Zinsstrukturkurve (langes Ende)', 'Cost of Carry / Forward-Preis']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'markets',
  'rates_impact',
  'anwendung',
  2,
  'Eine 10-jährige Staatsanleihe hat einen Kupon von 3 % und wird aktuell zu pari (100) gehandelt. Die Marktzinsen steigen um 100 Basispunkte. Wie verändert sich der Preis der Anleihe näherungsweise, wenn die Duration der Anleihe 8,5 Jahre beträgt?',
  'Bei einem Zinsanstieg von 100 Basispunkten (1 %) lässt sich die Preisveränderung näherungsweise mit der Modified Duration berechnen: ΔP ≈ –Duration × ΔY × P. Mit einer Duration von 8,5 und einem Ausgangspreis von 100 ergibt sich: ΔP ≈ –8,5 × 0,01 × 100 = –8,50. Der Anleihepreis fällt also von 100 auf ungefähr 91,50. Dieser Zusammenhang gilt, weil steigende Marktzinsen den Barwert der zukünftigen Cashflows der Anleihe reduzieren. Die Duration misst dabei die Zinssensitivität – je höher die Duration, desto stärker reagiert der Preis auf Zinsänderungen.',
  ARRAY['Modified Duration', 'ΔP = –Duration × ΔY × P', 'Preisrückgang ca. 8,5 Punkte (auf ~91,50)', 'Inverse Beziehung Zinsen/Anleihekurs', 'Basispunkte in Dezimal umrechnen (100 bp = 1 %)']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'markets',
  'rates_impact',
  'anwendung',
  4,
  'Ein Unternehmen hat eine festverzinsliche Anleihe mit einem Kupon von 4 %, einer Restlaufzeit von 10 Jahren und einer Modified Duration von 8,2 ausstehend. Die EZB erhöht die Leitzinsen unerwartet um 75 Basispunkte. Berechnen Sie die approximative Kursveränderung der Anleihe und erläutern Sie, warum der tatsächliche Kursverlust geringer ausfallen wird als Ihre Näherungsrechnung suggeriert.',
  'Die approximative Kursveränderung ergibt sich aus der Duration-Formel: ΔP/P ≈ −Modified Duration × Δy = −8,2 × 0,0075 = −6,15 %. Bei einem angenommenen Nominalwert von 100 entspricht das einem Kursverlust von ca. 6,15 Punkten. Der tatsächliche Kursverlust fällt jedoch geringer aus, weil die Kurs-Rendite-Beziehung konvex ist – dieses Phänomen wird als Konvexität bezeichnet. Die Duration-Approximation unterschätzt den Kursgewinn bei sinkenden Zinsen und überschätzt den Kursverlust bei steigenden Zinsen; der Konvexitätsterm (½ × Konvexität × Δy²) ist stets positiv und mildert den Verlust ab. Bei einem so großen Zinsschritt von 75 Basispunkten ist dieser Konvexitätsfehler besonders relevant und sollte in einer präzisen Bewertung berücksichtigt werden.',
  ARRAY['Modified Duration', 'Kursveränderung −6,15 %', 'Konvexität (Convexity)', 'Konvexitätsterm positiv / Verlust wird überschätzt', 'Nichtlineare Kurs-Rendite-Beziehung']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'markets',
  'rates_impact',
  'verstaendnis',
  2,
  'Wie wirkt sich ein Anstieg des allgemeinen Zinsniveaus auf die Anleihekurse aus, und warum ist das so?',
  'Wenn das allgemeine Zinsniveau steigt, fallen die Kurse bestehender Anleihen – und umgekehrt. Der Grund liegt darin, dass die fixen Kuponzahlungen einer bestehenden Anleihe im Vergleich zu neu emittierten Anleihen mit höheren Kupons weniger attraktiv werden. Um die Anleihe am Markt verkäuflich zu machen, muss ihr Kurs sinken, bis ihre Rendite (Yield) dem neuen Marktzinsniveau entspricht. Dieser inverse Zusammenhang zwischen Zinsen und Anleihekursen ist ein fundamentales Prinzip des Rentenmarktes. Das Ausmaß des Kursrückgangs hängt dabei maßgeblich von der Duration der Anleihe ab: Je länger die Laufzeit, desto stärker reagiert der Kurs auf Zinsänderungen.',
  ARRAY['Inverser Zusammenhang (Zinsen steigen → Kurse fallen)', 'Fixe Kuponzahlungen werden relativ unattraktiver', 'Yield muss dem Marktzinsniveau entsprechen', 'Duration bestimmt das Ausmaß der Kursreaktion']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'markets',
  'rates_impact',
  'verstaendnis',
  4,
  'Wenn die EZB die Leitzinsen unerwartet stark anhebt, würde man typischerweise erwarten, dass Anleihepreise fallen – doch unter welchen Umständen könnte eine solche Zinserhöhung paradoxerweise zu sinkenden Renditen am langen Ende der Zinskurve führen, und was sagt das über die Markterwartungen aus?',
  'Eine unerwartete Zinserhöhung kann am langen Ende der Kurve zu sinkenden Renditen führen, wenn der Markt die Maßnahme als glaubwürdiges Signal zur Inflationsbekämpfung interpretiert. In diesem Fall werden die langfristigen Inflationserwartungen nach unten revidiert, was den realen und nominalen Langfristzins drückt – ein klassisches „Bull Flattening" der Zinskurve. Der Markt preist dann ein, dass die Zentralbank durch entschlossenes Handeln heute künftige Zinserhöhungen überflüssig macht, sodass die erwarteten kurzfristigen Zinsen über den langen Zeithorizont im Schnitt sinken. Dieser Effekt tritt besonders dann auf, wenn die Zentralbank zuvor an Glaubwürdigkeit verloren hatte oder die Inflationserwartungen de-verankert waren. Es ist ein zentrales Beispiel dafür, dass der Transmissionsmechanismus der Geldpolitik über Erwartungen und nicht nur über aktuelle Zinssätze wirkt.',
  ARRAY['Bull Flattening', 'Inflationserwartungen', 'Zentralbank-Glaubwürdigkeit', 'Erwartungskanal / Transmissionsmechanismus', 'De-Verankerung der Erwartungen']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'markets',
  'sector_pitch',
  'wiedergabe',
  2,
  'Welche drei klassischen Kriterien sollte ein attraktiver Sektor erfüllen, wenn man ihn im Rahmen eines Sector Pitch im Investmentbanking vorstellt?',
  'Ein attraktiver Sektor für einen Sector Pitch sollte erstens ein starkes und nachhaltiges Wachstum aufweisen, das durch strukturelle Treiber wie Demografie, Regulierung oder Technologie gestützt wird. Zweitens sollte der Sektor eine hohe M&A-Aktivität oder ein klares Konsolidierungspotenzial besitzen, da dies direkte Relevanz für Investmentbanking-Mandante schafft. Drittens sind attraktive Bewertungsniveaus und eine hohe Kapitalmarktaktivität (z. B. IPOs, Kapitalerhöhungen) ein wichtiges Merkmal. Zusammen signalisieren diese Kriterien, dass der Sektor sowohl für Investoren als auch für Banken lukrative Transaktionsmöglichkeiten bietet.',
  ARRAY['Strukturelle Wachstumstreiber', 'M&A-Aktivität / Konsolidierungspotenzial', 'Bewertungsniveau', 'Kapitalmarktaktivität (IPOs, Kapitalerhöhungen)', 'Transaktionsrelevanz']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'markets',
  'sector_pitch',
  'wiedergabe',
  4,
  'Sie pitchen einen Sektor-Trade auf europäische Automobilwerte. Welche spezifischen Marktstruktur-Kennzahlen und Bewertungsmetriken würden Sie einem MD nennen, um zu begründen, warum der Sektor aktuell attraktiv oder unattraktiv bewertet ist – und welche Fallstricke gibt es bei der Verwendung des KGV als primäre Bewertungsmetrik für Automobilhersteller?',
  'Für einen Sektor-Pitch auf europäische Automobilwerte sind EV/EBITDA und EV/EBIT gegenüber dem KGV vorzuziehen, da OEMs typischerweise hohe Abschreibungen auf Sachanlagen und Entwicklungskosten aufweisen, die das Nettoergebnis stark verzerren. Das KGV ist zudem anfällig für zyklische Gewinneinbrüche – in Abschwungphasen steigt es optisch stark an und täuscht eine teure Bewertung vor, obwohl der Kurs bereits gefallen ist (sogenannte „Value Trap"). Ergänzend sollte man den Free Cash Flow Yield heranziehen, da Automobilhersteller kapitalintensiv sind und der operative Cash Flow nach hohen Capex-Anforderungen (Elektrifizierung, Plattforminvestitionen) erheblich vom EBITDA abweichen kann. Als sektorspezifische Kennzahlen sind Preis-zu-Buchwert (P/B) sowie die EBIT-Marge nach Segmenten (Automotive vs. Financial Services) relevant, um die Kernprofitabilität vom Finanzierungsgeschäft zu trennen. Schließlich muss der Net Cash/Debt-Status der industriellen Nettoliquidität separat betrachtet werden, da viele OEMs erhebliche Pensionsverpflichtungen und Leasingverbindlichkeiten tragen, die den Enterprise Value material beeinflussen.',
  ARRAY['EV/EBITDA bzw. EV/EBIT statt KGV (Abschreibungsverzerrung)', 'KGV-Fallstrick: Zyklizität / Value Trap', 'Free Cash Flow Yield (Capex-Intensität, Elektrifizierung)', 'Industrielle Nettoliquidität / Pensionsverpflichtungen (Enterprise Value)', 'Segmenttrennung Automotive vs. Financial Services (EBIT-Marge)']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'markets',
  'sector_pitch',
  'anwendung',
  2,
  'Sie analysieren einen Automobilzulieferer mit einem EBITDA von 200 Mio. € und einem Nettoverschuldungsgrad (Net Debt/EBITDA) von 3,0x. Der Sektor wird aktuell mit einem EV/EBITDA-Multiple von 6,0x gehandelt. Wie hoch ist der implizite Eigenkapitalwert (Equity Value) des Unternehmens, und wie würden Sie diesen einem potenziellen Investor pitchen?',
  'Der Enterprise Value des Unternehmens beträgt 200 Mio. € × 6,0x = 1.200 Mio. €. Die Nettoverschuldung ergibt sich aus 3,0x × 200 Mio. € = 600 Mio. €. Der implizite Eigenkapitalwert berechnet sich als EV minus Net Debt: 1.200 Mio. € − 600 Mio. € = 600 Mio. €. Im Pitch würde ich betonen, dass der Automobilzulieferer trotz des zyklischen Sektors stabile EBITDA-Margen aufweist, und den Equity Value im Kontext von Wachstumstreibern wie Elektromobilität oder Plattformkonsolidierung positionieren, um eine attraktive Investitionsthese zu untermauern.',
  ARRAY['Enterprise Value (EV = EBITDA × Multiple = 1.200 Mio. €)', 'Nettoverschuldung (Net Debt = 3,0x × 200 Mio. € = 600 Mio. €)', 'Equity Value (EV − Net Debt = 600 Mio. €)', 'Sektorspezifische Investitionsthese (z.B. Elektromobilität, Konsolidierung)', 'EV/EBITDA als Bewertungsmaßstab']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'markets',
  'sector_pitch',
  'anwendung',
  4,
  'Sie pitchen den europäischen Halbleitersektor. Unternehmen A hat ein EV/EBITDA von 18x bei 15 % EBITDA-Marge und 20 % Umsatzwachstum. Unternehmen B hat ein EV/EBITDA von 12x bei 25 % EBITDA-Marge und 5 % Umsatzwachstum. Welches Unternehmen würden Sie einem Wachstumsfonds empfehlen, und wie rechtfertigen Sie die Bewertungsprämie von Unternehmen A trotz der niedrigeren Marge?',
  'Für einen Wachstumsfonds würde ich Unternehmen A empfehlen, da das überlegene Umsatzwachstum von 20 % die niedrigere aktuelle Marge kompensiert – entscheidend ist die Frage, ob die Marge strukturell ausbaufähig ist (Operating Leverage). Die Bewertungsprämie von 18x vs. 12x lässt sich über eine PEG-Ratio-Logik rechtfertigen: Wächst A viermal schneller als B, ist das EV/EBITDA-to-Growth-Verhältnis von A (18x/20 = 0,9x) günstiger als das von B (12x/5 = 2,4x). Kritisch zu prüfen ist jedoch, ob das Wachstum von A auf skalierbaren Treibern basiert – etwa Design-Wins in KI-Chips oder Automotive – oder ob es zyklisch und damit nicht nachhaltig ist. Zudem muss der Wachstumsfonds das Margenprofil im Zeitverlauf modellieren: Erreicht A bei Skalierung eine Marge von 22–25 %, wäre die Prämie klar gerechtfertigt; bleibt die Marge strukturell niedrig, ist das Upside begrenzt. Ein strenger Investor würde außerdem den Free-Cashflow-Konversionsfaktor beider Unternehmen vergleichen, da hohe Wachstumsinvestitionen (Capex, R&D) die EBITDA-Qualität von A verwässern können.',
  ARRAY['PEG-Ratio / EV/EBITDA-to-Growth', 'Operating Leverage / Margenausbau', 'Nachhaltigkeit des Wachstums (strukturell vs. zyklisch)', 'Free-Cashflow-Konversion', 'Wachstumsfonds-Logik (Growth vs. Value)']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'markets',
  'sector_pitch',
  'verstaendnis',
  2,
  'Du pitchst den Technologiesektor als attraktives Investmentfeld. Welche strukturellen Treiber machen diesen Sektor aus Kapitalmarktsicht grundsätzlich interessant?',
  'Der Technologiesektor profitiert von mehreren strukturellen Wachstumstreibern: Erstens ermöglichen skalierbare Geschäftsmodelle – insbesondere bei Software und Plattformen – überproportionales Umsatzwachstum bei geringen Grenzkosten, was zu hohen Margen führt. Zweitens erzeugen Netzwerkeffekte und hohe Switching Costs starke Wettbewerbsvorteile und eine stabile Kundenbindung. Drittens treibt die fortschreitende Digitalisierung quer durch alle Branchen eine strukturell hohe Nachfrage nach Tech-Produkten und -Dienstleistungen. Schließlich generieren führende Technologieunternehmen oft erhebliche Free Cashflows, die Aktienrückkäufe, M&A und weitere Reinvestitionen finanzieren – was den Sektor auch aus Renditegesichtspunkten attraktiv macht.',
  ARRAY['Skalierbare Geschäftsmodelle / geringe Grenzkosten', 'Netzwerkeffekte', 'Switching Costs / Wettbewerbsvorteile', 'Digitalisierung als struktureller Nachfragetreiber', 'Free Cashflow-Generierung']::text[]
);
INSERT INTO public.ib_questions (topic, archetype, question_type, difficulty_level, prompt, optimal_answer, key_points)
VALUES (
  'markets',
  'sector_pitch',
  'verstaendnis',
  4,
  'Du pitchst den europäischen Halbleitersektor als attraktives Investment. Ein MD hält dagegen: „Halbleiter sind ein zyklisches Commodity-Business mit strukturell niedrigen Margen – warum sollte ich da jetzt einsteigen?" Wie entkräftest du diesen Einwand, und wo siehst du die echten Risiken deiner These?',
  'Der Einwand vermischt zwei strukturell unterschiedliche Segmente: Während Memory-Chips tatsächlich stark zyklisch und margenschwach sind, operieren europäische Champions wie ASML oder Infineon in oligopolistischen Nischen mit hohen Switching Costs und pricing power – ASMLs EUV-Monopol ist das deutlichste Beispiel. Der aktuelle Einstiegszeitpunkt ist zudem durch einen Lagerabbau-Zyklus begründet, der sich dem Ende nähert, kombiniert mit strukturellen Wachstumstreibern wie AI-Infrastruktur, Automotive-Elektrifizierung und europäischer Chip-Souveränität (EU Chips Act). Die echten Risiken meiner These liegen in der Abhängigkeit von TSMC für die Fertigung, einer möglichen Eskalation der US-China-Exportrestriktionen, die europäische Zulieferer direkt treffen, sowie einer Überschätzung der AI-Capex-Nachhaltigkeit. Ich würde daher selektiv auf Ausrüster und Analog-/Power-Chips setzen statt auf undifferenzierte Sektorexposure.',
  ARRAY['Segmentdifferenzierung (Memory vs. Ausrüster/Analog)', 'Oligopol / Pricing Power / Switching Costs', 'Zykluspositionierung (Lagerabbau)', 'Strukturelle Wachstumstreiber (AI, Automotive, EU Chips Act)', 'Exportrestriktionen / Geopolitik als Gegenrisiko']::text[]
);